  `title_style` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT '',
  `summary_length` varchar(32) COLLATE utf8mb4_unicode_ci DEFAULT 'both',
  `candidate_titles` json DEFAULT NULL,
  `summary_short` text COLLATE utf8mb4_unicode_ci,
  `summary_long` text COLLATE utf8mb4_unicode_ci,
  `summary_points` json DEFAULT NULL,
  `keywords` json DEFAULT NULL,
  `news_elements` json DEFAULT NULL,
  `risk_level` varchar(32) COLLATE utf8mb4_unicode_ci DEFAULT 'low',
