  KEY `idx_ai_generate_record_source` (`source`),
  KEY `idx_ai_generate_record_source_title` (`source_title`)
) ENGINE=InnoDB AUTO_INCREMENT=62 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
