INSERT INTO `ai_generate_record` VALUES (1,1,'news',1,'人工智能技术加速落地，多行业探索智能化转型','人工智能技术正在从模型能力展示走向产业应用，多个行业开始探索智能化升级路径。',3,'generate','formal','','both','[\"人工智能技术加速落地，多行业探索智能化转型\", \"AI产业应用深入推进，各行业加速智能化升级\", \"大模型走向实际场景，人工智能推动产业变革\"]','人工智能技术正从模型展示走向产业应用，新闻、教育、医疗、制造、交通等多领域开始探索智能化升级，有望推动各行业数字化转型。','近年来，人工智能技术快速发展，大模型、智能问答、内容生成和数据分析等能力逐渐进入实际业务场景。在新闻、教育、医疗、制造和交通等领域，相关企业和机构正在探索如何利用人工智能提高效率、降低成本并改善用户体验。业内人士认为，随着基础设施、算法能力和应用生态不断完善，人工智能将进一步推动各行业数字化转型。','[\"人工智能技术快速发展，大模型等能力进入实际业务场景\", \"新闻、教育、医疗、制造、交通等多领域探索智能化应用\", \"基础设施、算法能力和应用生态完善将推动产业数字化转型\"]','[\"人工智能\", \"大模型\", \"智能化转型\", \"产业应用\"]',NULL,'low',NULL,'mock',1,'2026-06-27 11:40:43','2026-06-27 11:40:43','2026-01-15 11:00:00','2026-06-27 11:40:43'),(2,1,'news',2,'低空经济发展提速，无人机应用场景不断拓展','低空经济成为新兴产业关注点，无人机物流、巡检、测绘等应用不断扩展。',3,'generate','concise','','both','[\"低空经济发展提速，无人机应用场景不断拓展\", \"无人机应用持续扩展，低空经济迎来发展机遇\", \"政策基础设施逐步完善，低空经济蓄势待发\"]','低空经济正成为新质生产力重要方向，无人机在物流、植保、救援、巡检、城市治理等场景应用价值凸显，需统筹空域管理、飞行安全、产业标准和商业模式创新。','随着相关政策和基础设施不断完善，低空经济正在成为多个地区培育新质生产力的重要方向。无人机在物流配送、农业植保、应急救援、电力巡检和城市治理等场景中展现出较强应用价值。专家表示，低空经济的发展需要统筹空域管理、飞行安全、产业标准和商业模式创新。','[\"政策基础设施完善推动低空经济成为新质生产力方向\", \"无人机在物流、植保、救援、巡检等多场景展现应用价值\", \"低空经济发展需统筹空域管理、安全、标准和商业模式\"]','[\"低空经济\", \"无人机\", \"产业发展\", \"空域管理\"]',NULL,'low',NULL,'mock',1,'2026-06-27 11:40:43','2026-06-27 11:40:43','2026-01-16 10:00:00','2026-06-27 11:40:43'),(3,2,'news',3,'新能源汽车市场持续增长，智能交通生态加快形成','新能源汽车销量增长带动充电、智能驾驶和交通服务生态持续完善。',3,'generate','formal','','both','[\"新能源汽车市场持续增长，智能交通生态加快形成\", \"新能源汽车产业协同升级，智能交通生态逐步完善\", \"新能源车带动产业链发展，智慧交通系统加速构建\"]','新能源汽车产业快速发展，带动动力电池、充电基础设施、智能驾驶和车联网等产业协同升级，推动城市交通系统更加高效和低碳。','新能源汽车产业近年来保持较快发展，带动动力电池、充电基础设施、智能驾驶和车联网等相关产业协同升级。随着车辆智能化水平提升，交通管理、能源补给和出行服务也在发生变化。业内认为，新能源汽车与智能交通的结合将推动城市交通系统更加高效和低碳。','[\"新能源汽车产业快速发展，带动相关产业协同升级\", \"车辆智能化推动交通管理、能源补给和出行服务变革\", \"新能源汽车与智能交通结合推动城市交通高效低碳发展\"]','[\"新能源汽车\", \"智能交通\", \"低碳出行\", \"车联网\"]',NULL,'low',NULL,'mock',1,'2026-06-27 11:40:43','2026-06-27 11:40:43','2026-01-15 15:30:00','2026-06-27 11:40:43'),(47,3,'manual',NULL,'','随后，场边记者米格尔-安赫尔-迪亚斯透露，巴尔韦德被换下后坐在替补席上“哭了”，身边的队友正在安慰他。这一消息很快引发演播室内的讨论，其中反应最激烈的是马诺洛-拉马。\n\n拉马对这名皇马中场的态度感到不满，并在节目中直言：“告诉巴尔韦德，差不多得了。他这一年都这样，不愿意热身，不想踢边后卫，还让哈维-阿隆索过得很难。”\n\n最后，拉马继续说道：“也该告诉巴尔韦德了，让他稍微收一收吧。”',3,'generate','简明扼要','客观新闻型','both','[\"随后，场边记者米格尔-安赫尔-迪亚斯透露，巴尔韦德被换下后坐...\", \"这一消息很快引发演播室内的讨论，其中反应最激烈的是马诺洛-拉...\", \"拉马对这名皇马中场的态度感到不满，并在节目中直言：“告诉巴尔...\"]','随后，场边记者米格尔-安赫尔-迪亚斯透露，巴尔韦德被换下后坐在替补席上“哭了”，身边的队友正在安慰他这一消息很快引发演播室内的讨论，其中反应最激烈的是马诺洛-拉...','本文详细介绍了拉马对这名皇马中场的态度感到不满、这一消息很快引发演播室内的讨论、巴尔韦德被换下后坐在替补席上的最新发展。随后，场边记者米格尔-安赫尔-迪亚斯透露，巴尔韦德被换下后坐在替补席上“哭了”，身边的队友正在安慰他这一消息很快引发演播室内的讨论，其中反应最激烈的是马诺洛-拉马拉马对这名皇马中场...','[\"相关内容涉及拉马对这名皇马中场的态度感到不满方面的重要突破\", \"相关内容涉及这一消息很快引发演播室内的讨论方面的重要突破\", \"相关内容涉及巴尔韦德被换下后坐在替补席上方面的重要突破\"]','[\"拉马对这名皇马中场的态度感到不满\", \"这一消息很快引发演播室内的讨论\", \"巴尔韦德被换下后坐在替补席上\", \"其中反应最激烈的是马诺洛\", \"身边的队友正在安慰他\"]','{\"how\": \"拉马对这名皇马中场的态度感到不满，并在节目中直言：“告诉巴尔\", \"who\": \"随后\", \"why\": \"为了推进拉马对这名皇马中场的态度感到不满的发展\", \"what\": \"随后，场边记者米格尔-安赫尔-迪亚斯透露，巴尔韦德被换下后坐在替补席上“哭了”，身边的队友正在安慰他\", \"when\": \"近期\", \"where\": \"相关地区\"}','low','{\"score\": 90, \"issues\": [\"文本结构良好\"], \"risk_level\": \"low\", \"suggestions\": [\"文本质量满足生成条件\"]}','mock',1,'2026-06-29 17:27:52','2026-06-29 17:27:52','2026-06-29 17:27:52','2026-06-29 17:27:52'),(49,3,'manual',NULL,'','随后，场边记者米格尔-安赫尔-迪亚斯透露，巴尔韦德被换下后坐在替补席上“哭了”，身边的队友正在安慰他。这一消息很快引发演播室内的讨论，其中反应最激烈的是马诺洛-拉马。\n\n拉马对这名皇马中场的态度感到不满，并在节目中直言：“告诉巴尔韦德，差不多得了。他这一年都这样，不愿意热身，不想踢边后卫，还让哈维-阿隆索过得很难。”\n\n最后，拉马继续说道：“也该告诉巴尔韦德了，让他稍微收一收吧。”',3,'generate','简明扼要','客观新闻型','both','[\"随后，场边记者米格尔-安赫尔-迪亚斯透露，巴尔韦德被换下后坐...\", \"这一消息很快引发演播室内的讨论，其中反应最激烈的是马诺洛-拉...\", \"拉马对这名皇马中场的态度感到不满，并在节目中直言：“告诉巴尔...\"]','随后，场边记者米格尔-安赫尔-迪亚斯透露，巴尔韦德被换下后坐在替补席上“哭了”，身边的队友正在安慰他这一消息很快引发演播室内的讨论，其中反应最激烈的是马诺洛-拉...','本文详细介绍了拉马对这名皇马中场的态度感到不满、这一消息很快引发演播室内的讨论、巴尔韦德被换下后坐在替补席上的最新发展。随后，场边记者米格尔-安赫尔-迪亚斯透露，巴尔韦德被换下后坐在替补席上“哭了”，身边的队友正在安慰他这一消息很快引发演播室内的讨论，其中反应最激烈的是马诺洛-拉马拉马对这名皇马中场...','[\"相关内容涉及拉马对这名皇马中场的态度感到不满方面的重要突破\", \"相关内容涉及这一消息很快引发演播室内的讨论方面的重要突破\", \"相关内容涉及巴尔韦德被换下后坐在替补席上方面的重要突破\"]','[\"拉马对这名皇马中场的态度感到不满\", \"这一消息很快引发演播室内的讨论\", \"巴尔韦德被换下后坐在替补席上\", \"其中反应最激烈的是马诺洛\", \"身边的队友正在安慰他\"]','{\"how\": \"拉马对这名皇马中场的态度感到不满，并在节目中直言：“告诉巴尔\", \"who\": \"随后\", \"why\": \"为了推进拉马对这名皇马中场的态度感到不满的发展\", \"what\": \"随后，场边记者米格尔-安赫尔-迪亚斯透露，巴尔韦德被换下后坐在替补席上“哭了”，身边的队友正在安慰他\", \"when\": \"近期\", \"where\": \"相关地区\"}','low','{\"score\": 90, \"issues\": [\"文本结构良好\"], \"risk_level\": \"low\", \"suggestions\": [\"文本质量满足生成条件\"]}','mock',1,'2026-06-29 17:29:20','2026-06-29 17:29:20','2026-06-29 17:29:20','2026-06-29 17:29:20'),(50,3,'manual',NULL,'','虎扑06月28日讯 在乌拉圭对阵西班牙的比赛转播中，巴尔韦德被换下后落泪一事引发了科贝电台评论员马诺洛-拉马的强烈批评。\n\n在科贝电台《Tiempo de Juego》节目转播这场比赛时，乌拉圭主帅贝尔萨做出换人调整，用前锋费德里科-比尼亚斯换下乌拉圭队长巴尔韦德。对于贝尔萨的这一决定，节目中有人评价称，阿根廷教练“手一点都不抖”。',3,'generate','简明扼要','客观新闻型','both','[\"虎扑06月28日讯 在乌拉圭对阵西班牙的比赛转播中，巴尔韦德...\", \"在科贝电台《Tiempo de Juego》节目转播这场比赛...\", \"对于贝尔萨的这一决定，节目中有人评价称，阿根廷教练“手一点都...\"]','虎扑06月28日讯 在乌拉圭对阵西班牙的比赛转播中，巴尔韦德被换下后落泪一事引发了科贝电台评论员马诺洛-拉马的强烈批评在科贝电台《Tiempo de Juego...','本文详细介绍了巴尔韦德被换下后落泪一事引发了科贝电台评论员马诺洛、在乌拉圭对阵西班牙的比赛转播中、比尼亚斯换下乌拉圭队长巴尔韦德的最新发展。虎扑06月28日讯 在乌拉圭对阵西班牙的比赛转播中，巴尔韦德被换下后落泪一事引发了科贝电台评论员马诺洛-拉马的强烈批评在科贝电台《Tiempo de Juego...','[\"相关内容涉及巴尔韦德被换下后落泪一事引发了科贝电台评论员马诺洛方面的重要突破\", \"相关内容涉及在乌拉圭对阵西班牙的比赛转播中方面的重要突破\", \"相关内容涉及比尼亚斯换下乌拉圭队长巴尔韦德方面的重要突破\"]','[\"巴尔韦德被换下后落泪一事引发了科贝电台评论员马诺洛\", \"在乌拉圭对阵西班牙的比赛转播中\", \"比尼亚斯换下乌拉圭队长巴尔韦德\", \"乌拉圭主帅贝尔萨做出换人调整\", \"对于贝尔萨的这一决定\"]','{\"how\": \"对于贝尔萨的这一决定，节目中有人评价称，阿根廷教练“手一点都\", \"who\": \"虎扑\", \"why\": \"为了推进巴尔韦德被换下后落泪一事引发了科贝电台评论员马诺洛的发展\", \"what\": \"虎扑06月28日讯 在乌拉圭对阵西班牙的比赛转播中，巴尔韦德被换下后落泪一事引发了科贝电台评论员马诺洛-拉马的强烈批评\", \"when\": \"近期\", \"where\": \"相关地区\"}','low','{\"score\": 90, \"issues\": [\"文本结构良好\"], \"risk_level\": \"low\", \"suggestions\": [\"文本质量满足生成条件\"]}','mock',1,'2026-06-29 17:31:34','2026-06-29 17:31:34','2026-06-29 17:31:34','2026-06-29 17:31:34'),(51,3,'manual',NULL,'','第五部分单元模块设计\n一、新闻数据采集与数据库支撑设计\n1、新闻数据采集设计\n本项目的数据来源主要包括系统预置数据、RSS新闻爬虫、用户手动输入文本、用户上传文件以及社区用户生成内容，以MySQL业务数据库作为系统运行的主要数据基础。系统围绕新闻浏览、AI标题摘要生成、社区互动、个人中心管理、Timeline事件脉络生成等功能，组织新闻、用户、评论、点赞、收藏、AI生成记录、话题和时间线等数据。\n当前系统采用“数据库优先+Mock兜底”的双轨运行模式。MySQL正常且数据表中存在业务数据时，后端优先读取数据库；当数据库异常、数据不足或局部模块尚未完成真实数据接入时，后端自动回退到backend/app/mock目录中的Mock数据，保证系统演示流程不中断。该设计既符合项目实训阶段的联调需要，也便于后续逐步替换为完全真实的数据驱动模式。\n\n图5-1新闻数据采集与入库流程\n2、新闻数据入库与清洗流程\nRSS新闻采集由scripts/crawlers/rss_news_crawler.py完成。爬虫脚本定时或手动读取RSS源，解析新闻标题、摘要、原文链接、发布时间和来源名称，并进一步访问原文页面提取正文、封面图和更多元信息。系统根据source_url判断新闻是否已入库，避免重复插入；若正文提取失败，则使用RSS摘要作为正文兜底内容。\n新闻入库时，系统会尝试根据分类规则或关键词映射确定category_id，并根据news_topic表中的keyword_list尝试匹配topic_id。若暂时无法匹配到话题，topic_id可以为空，后续由审核/编辑在后台进行手动归类或批量绑定。每次爬虫执行结果写入crawl_log表，用于记录解析数量、新增数量、跳过数量、失败数量和错误信息。\n\n3、数据库文件与初始化协作要求\n项目数据库文件统一放置在database目录下，主要包括schema.sql、seed.sql和migrations目录。其中schema.sql用于创建完整表结构，seed.sql用于导入测试账号、新闻分类、示例新闻、话题和热搜数据，migrations目录用于保存后续新增字段或新增表的迁移脚本。组员首次搭建数据库时，应先执行schema.sql，再执行seed.sql，最后按需要执行migrations脚本。\n\n二、人工智能技术方案\n1、AI微服务技术路线\n本项目的AI能力由独立ai-service提供。ai-service采用FastAPI构建，内部通过OpenAISDK兼容方式调用智谱GLM-4-Flash大模型，同时保留Mock回退机制。后端backend并不直接在业务模块中调用模型，而是通过HTTP/JSON调用ai-service，由ai-service统一完成Prompt构造、模型调用、结果解析和异常兜底。\nai-service的真实目录结构包括routers、schemas、services、mock和core等部分。services目录中的llm_client.py负责大模型客户端调用，prompt_builder.py负责Prompt构造，llm_parser.py负责解析模型返回结果，generate_service.py、extract_service.py、check_service.py、chat_service.py和timeline_service.py分别对应标题摘要生成、新闻要素提取、一致性校验、新闻助手对话和Timeline事件脉络生成。\n\n图5-2AI标题摘要生成调用流程\n2、AI标题摘要生成设计\nAI标题摘要生成是系统的核心功能之一。用户可以在AI生成页面中手动输入新闻正文，也可以从新闻详情页一键导入正文。前端通过frontend/src/api/ai.ts调用后端/api/ai/generate接口，后端modules/ai/service.py对输入文本和生成参数进行校验，然后调用ai-service的generate路由完成标题、摘要、关键词、新闻要素和一致性校验结果生成。\n生成完成后，后端将候选标题、短摘要、长摘要、摘要要点、关键词、新闻要素、风险等级和一致性检查结果写入ai_generate_record表，供个人中心的AI生成历史页面查询和复用。若大模型调用失败，ai-service将回退到mock/sample_outputs.py中的Mock示例输出，从而保证前端页面能够正常展示生成结果。\n\n3、Timeline事件脉络生成设计\nTimeline事件脉络模块用于解决热点事件新闻分散、用户难以把握发展过程的问题。前端通过frontend/src/api/timeline.ts和timeline组件请求后端timeline模块。后端modules/timeline/service.py根据topic_id优先查询event_timeline表中的缓存数据，若缓存不存在或后台触发刷新，则查询news_topic和news表，按publish_time对相关稿件排序，拼接事件上下文后调用ai-service/app/services/timeline_service.py生成结构化时间线节点。\nTimeline模块的核心数据表包括news_topic、news和event_timeline。news_topic保存话题名称、简介和关键词；news表通过topic_id关联话题；event_timeline保存生成后的timeline_json、source_news_ids和生成状态。普通用户主要使用查询接口查看时间线，审核/编辑和管理员可通过后台接口刷新事件脉络、修改单条新闻topic_id或批量归类新闻。\n\n图5-3Timeline事件脉络生成流程\n三、Web端单元UI设计\n本项目采用B/S架构，前端全部基于Vue3、TypeScript、Vite、VueRouter、Pinia、ElementPlus和Axios实现，不包含PyQt桌面端。系统所有功能均通过浏览器访问，前端代码位于frontend/src目录下，页面视图位于views目录，公共组件位于components目录，接口封装位于api目录，状态管理位于stores目录。\n系统页面采用统一MainLayout.vue布局，由顶部导航栏、左侧新闻分类栏和主内容区组成。顶部导航栏包含系统名称、首页、AI生成、社区、个人中心、管理后台、搜索框、明暗模式切换按钮和用户角色标识；左侧分类栏展示推荐、时政、社会、财经、科技、体育、娱乐等新闻分类，并预留生成历史和订阅管理入口。\n\n图5-4Web端单元UI结构\n\n四、后端数据访问封装设计\n1、当前实现结构说明\n本项目采用更符合FastAPI项目实际的轻量化模块结构：每个业务模块位于backend/app/modules目录下，并按照router.py、schema.py、service.py进行组织。其中router.py负责路由定义，schema.py负责Pydantic请求与响应模型，service.py负责业务逻辑处理和数据库访问调用。\n数据库连接与SQL执行统一封装在backend/app/db/database.py中。该文件基于PyMySQL管理MySQL连接，并提供execute_query、execute_one、execute_update等通用方法。各业务模块的service.py调用这些方法完成数据查询、单条查询和写入更新操作。该设计减少了目录复杂度，符合当前项目“数据库优先+Mock兜底”的实际运行方式。\n\n图5-5后端模块与数据库访问封装关系\n\n2、各模块数据访问说明\nauth模块负责登录鉴权，优先读取user表，并兼容mock-token-user、mock-token-editor、mock-token-admin等演示token。user模块负责用户基础信息读取。news模块负责新闻分类、新闻列表、新闻详情和热榜数据查询，主要访问news_category、news、news_topic和hot_topic等表。\ninteraction模块负责点赞、收藏、评论和浏览记录，主要访问news_comment、user_like、favorite和browse_history等表。ai模块负责调用ai-service并将生成结果写入ai_generate_record表。timeline模块负责话题列表、时间线节点和来源新闻关联，主要访问news_topic、news和event_timeline表。community模块负责社区帖子、帖子评论、热搜和拉黑关系，主要访问community_post、post_comment、user_like、favorite、user_block和hot_topic等表。profile模块负责个人中心数据汇总，admin模块负责管理后台内容审核、用户管理、热搜维护、话题归类和系统配置。\n五、业务逻辑层设计\n1、业务模块总体结构\n业务逻辑层是backend服务的核心部分。项目在backend/app/main.py中完成CORS配置、异常处理器注册和9个业务模块路由注册。各模块采用router.py、schema.py、service.py的统一结构，既保证了模块职责清晰，又便于多人并行开发。\n\n2、核心模块详细说明\nauth模块通过user表完成用户名、密码和角色读取，登录成功后返回统一格式的用户信息和token。当前阶段仍兼容Mock登录，便于user、editor、admin三种角色快速演示。router层负责接收登录请求，schema层约束用户名和密码参数，service层完成数据库查询、密码校验和兜底逻辑。\nnews模块负责首页和详情页的数据支撑。首页加载时，news模块读取news_category表返回分类，读取news表返回新闻卡片数据，并结合hot_topic表返回新闻热榜Top10。用户进入新闻详情页时，news或interaction模块会记录browse_history，并更新news.view_count。新闻详情页还可调用AI入口，将当前新闻内容传递给AI生成页面。\ninteraction模块封装点赞、收藏、评论、回复和浏览记录功能。点赞数据写入user_like表，收藏数据写入favorite表，新闻评论写入news_comment表，浏览历史写入browse_history表。由于user_like和favorite均采用target_type+target_id的多态设计，因此同一套表结构可以支持新闻、评论、社区帖子和帖子评论等多种目标。\nai模块是backend与ai-service的桥接模块。前端提交生成请求后，backend/modules/ai/service.py使用httpx调用ai-service。ai-service返回结构化结果后，backend将结果写入ai_generate_record表，并按照统一ApiResponse格式返回前端。该模块保证前端无需关心真实大模型调用细节。\ntimeline模块负责多源事件脉络功能。用户请求某topic_id的时间线时，timeline模块优先读取event_timeline缓存；若缓存不存在，则查询news表中同topic_id的新闻，调用ai-service的timeline_service.py生成时间线，再写回event_timeline表。管理后台可以触发刷新接口，重新生成某个话题的事件脉络。\ncommunity模块负责社区互动业务，包括帖子发布、帖子列表、帖子评论、点赞收藏、用户拉黑和热搜话题展示。profile模块负责个人中心数据聚合，包括浏览历史、收藏记录、评论记录、AI生成历史和分类订阅。admin模块面向审核/编辑和管理员，承担内容审核、用户管理、话题维护、热搜配置和系统管理功能。\n3、RSS爬虫脚本设计\nRSS爬虫脚本位于scripts/crawlers/rss_news_crawler.py，不属于backend/app/modules中的Web路由模块，但它是新闻数据来源的重要组成部分。该脚本支持RSS解析、新闻去重、正文解析、封面图提取、爬虫日志记录和旧新闻归档。执行完成后，新闻数据写入news表，执行日志写入crawl_log表，前端页面即可通过后端新闻接口读取新入库新闻。\n第六部分数据库设计\n一、数据库整体结构\n本项目数据库用于支撑《基于大语言模型的智能新闻摘要与协同互动系统》的核心业务数据存储，包括用户账号、新闻内容、新闻互动、AI生成记录、社区讨论、个人中心、RSS爬虫日志、Timeline事件脉络以及用户分类订阅等模块。数据库采用MySQL8.0，字符集统一使用utf8mb4，排序规则使用utf8mb4_unicode_ci，存储引擎统一采用InnoDB。\n数据库名称建议为llm_news_system。当前系统采用“数据库优先+Mock兜底”的方式运行。MySQL正常时，后端优先读写数据库；当数据库异常或部分模块数据不足时，后端回退到Mock数据，保证系统演示流程不中断。\n\n图6-1数据库核心关系结构图\n\n二、用户与权限管理\n1、user表结构\nuser表用于保存系统用户账号信息，包括普通用户、审核/编辑和管理员。该表是登录认证、权限控制、个人中心、社区发帖、点赞收藏和后台管理的基础表。当前系统优先从user表读取登录用户信息，同时兼容Mocktoken。\n系统预置测试账号包括user/123456、editor/123456和admin/123456，分别对应普通用户、审核/编辑和管理员角色。\n三、新闻内容管理\n1、news_category表结构\nnews_category表用于存储新闻分类信息，支撑首页左侧分类栏、分类筛选和分类高亮功能。系统预置分类包括推荐、时政、社会、财经、科技、体育、娱乐、国际等。\n\n2、news_topic表结构\nnews_topic表用于保存新闻话题，是Timeline事件脉络生成的基础表。一条话题可以关联多篇新闻，新闻通过news.topic_id与该表关联。keyword_list使用JSON格式保存关键词列表，用于自动打标和话题聚合。\n\n3、news表结构\nnews表是系统最核心的数据表，用于保存新闻标题、摘要、正文、封面图、来源、分类、话题、统计量和原文链接等信息。RSS爬虫抓取到的真实新闻最终写入该表。source_url用于新闻去重，topic_id用于Timeline聚合，category_id用于分类筛选。\n\nnews表中不建议直接保存source_name和topic_name。source_name可以由source字段表示，topic_name应通过topic_id关联news_topic表获得。后端接口如需返回这些展示字段，可在查询时通过字段映射或JOIN生成。\n四、新闻互动与个人行为管理\n1、news_comment表结构\nnews_comment表用于保存新闻详情页中的用户评论和回复。通过parent_id实现一级评论和回复评论。\n\n2、user_like表结构\nuser_like是通用点赞表，用于记录用户对新闻、新闻评论、社区帖子和帖子评论等不同目标的点赞行为。该表通过user_id、target_type、target_id组合避免重复点赞。\n\n3、favorite表结构\nfavorite是通用收藏表，用于记录用户收藏新闻、社区帖子或AI记录的行为。该表支撑新闻收藏、社区帖子收藏、个人中心收藏记录和收藏状态判断。\n\n4、browse_history表结构\nbrowse_history表用于记录用户浏览过的新闻。用户打开新闻详情页时，系统写入或更新浏览记录；个人中心的浏览历史页面从该表读取数据。\n\n五、AI生成与文件上传管理\n1、ai_generate_record表结构\nai_generate_record表用于保存用户在AI标题摘要生成页面中的生成历史。用户输入新闻正文或从新闻详情页导入正文后，AI生成的候选标题、摘要、关键词、新闻要素和一致性检查结果会保存到该表中。\n\n2、upload_file表结构\nupload_file表用于保存用户上传文件的基本信息。数据库中只保存文件元数据，实际文件可保存在服务器本地目录或后续对象存储中。\n\n六、社区协同互动管理\n1、community_post表结构\ncommunity_post表用于保存用户在社区页面发布的帖子。帖子可以关联新闻，也可以关联Timeline话题。该表支撑帖子列表、发帖、帖子详情、热度排序和管理后台审核。\n\n2、post_comment表结构\npost_comment表用于保存社区帖子下的评论和回复，通过parent_id支持评论回复结构。\n\n3、user_block表结构\nuser_block表用于保存用户之间的拉黑关系。社区列表加载时，系统可根据当前用户的拉黑记录过滤对应用户发布的帖子和评论。\n\n七、热搜与Timeline管理\n1、hot_topic表结构\nhot_topic表用于保存首页、社区或侧边栏展示的热搜内容。target_type可以指向新闻、新闻话题或社区帖子，用于形成热榜入口和事件脉络入口。\n\n2、event_timeline表结构\nevent_timeline表用于保存某个话题下的事件时间线生成结果，是Timeline模块的缓存表。后端timeline模块优先从该表读取数据；当缓存不存在或后台刷新时，再调用ai-service的timeline_service.py生成新的时间线结果。\n\n八、RSS爬虫与用户订阅管理\n1、crawl_log表结构\ncrawl_log表用于记录RSS新闻爬虫每次执行的结果，由scripts/crawlers/rss_news_crawler.py写入。该表可用于判断爬虫是否正常运行，并为后续管理后台展示爬虫状态提供数据支撑。\n\n2、user_category_subscription表结构\nuser_category_subscription表由migration005创建，用于保存用户订阅的新闻分类，支撑侧边栏订阅管理和后续个性化推荐。\n\n九、主要外键与关系说明\n本项目数据库整体上围绕user、news、news_topic、community_post和ai_generate_record等核心表展开。由于当前阶段仍兼容mock兜底，部分外键可以先采用应用层约束，后续数据库稳定后再逐步增加物理外键约束。\n',3,'generate','简明扼要','客观新闻型','both','[\"第五部分单元模块设计\", \"一、新闻数据采集与数据库支撑设计\", \"1、新闻数据采集设计\"]','第五部分单元模块设计一、新闻数据采集与数据库支撑设计','本文详细介绍了表结构、目录、主要访问的最新发展。第五部分单元模块设计一、新闻数据采集与数据库支撑设计1、新闻数据采集设计这些进展在多个方面具有重要意义，有望在后续相关领域产生深远影响。','[\"相关内容涉及表结构方面的重要突破\", \"相关内容涉及目录方面的重要突破\", \"相关内容涉及主要访问方面的重要突破\"]','[\"表结构\", \"目录\", \"主要访问\", \"兜底\", \"摘要\"]','{\"how\": \"1、新闻数据采集设计\", \"who\": \"第五部分单元模块设计\", \"why\": \"为了推进表结构的发展\", \"what\": \"第五部分单元模块设计\", \"when\": \"近期\", \"where\": \"乐、国\"}','medium','{\"score\": 70, \"issues\": [\"文本中同时出现\'增加\'和\'减少\'，可能存在表述冲突\", \"文本中同时出现\'成功\'和\'失败\'，可能存在表述冲突\"], \"risk_level\": \"medium\", \"suggestions\": [\"请检查原文是否表述清晰，避免歧义\", \"请检查原文是否表述清晰，避免歧义\"]}','mock',1,'2026-06-29 17:35:14','2026-06-29 17:35:14','2026-06-29 17:35:14','2026-06-29 17:35:14'),(52,3,'manual',NULL,'','虎扑06月29日讯 今日，詹姆斯更新INS晒出打高尔夫球时搞怪表情。\n\n美媒NBA Memes晒出詹姆斯白胡子调侃：74岁的勒布朗-詹姆斯刚刚发布了一张自拍👴🏾。\n\n据此前Shams报道，湖人在交易方面非常积极，但就勒布朗-詹姆斯的自由球员身份而言，湖人目前还没有向他发出任何续约报价。\n\n25-26赛季詹姆斯年薪为5262万美元，场均得到20.9分6.1篮板7.2助攻1.2抢断0.6盖帽。',3,'generate','简明扼要','客观新闻型','both','[\"詹姆斯晒高尔夫搞怪自拍，调侃74岁高龄\", \"湖人积极交易未向詹姆斯报价，球员晒白胡子自拍\", \"詹姆斯年薪5262万，场均20.9分，晒搞怪高尔夫自拍\"]','NBA球星勒布朗-詹姆斯在社交媒体上晒出打高尔夫时的搞怪自拍，调侃自己74岁高龄。湖人队虽然积极寻求交易，但尚未向詹姆斯提供续约报价。','NBA球星勒布朗-詹姆斯在社交媒体上更新了自己的Instagram，晒出了一张自己打高尔夫时的搞怪自拍，并调侃自己已经74岁高龄。据此前报道，湖人队虽然积极寻求交易，但尚未向詹姆斯提供续约报价。詹姆斯在25-26赛季的年薪为5262万美元，场均得到20.9分、6.1篮板、7.2助攻、1.2抢断和0.6盖帽。','[\"詹姆斯晒高尔夫搞怪自拍，调侃自己74岁高龄\", \"湖人队积极交易，但尚未向詹姆斯提供续约报价\", \"詹姆斯在25-26赛季场均数据出色\"]','[\"詹姆斯\", \"高尔夫\", \"湖人队\", \"续约\", \"自拍\", \"交易\", \"年薪\", \"场均数据\"]','{\"how\": \"通过晒自拍\", \"who\": \"勒布朗-詹姆斯\", \"why\": \"无\", \"what\": \"晒高尔夫搞怪自拍，调侃自己74岁高龄\", \"when\": \"06月29日\", \"where\": \"社交媒体Instagram\"}','low','{\"score\": 85, \"issues\": [\"无\"], \"risk_level\": \"low\", \"suggestions\": [\"无\"]}','mock',1,'2026-06-29 18:57:57','2026-06-29 18:57:57','2026-06-29 18:57:57','2026-06-29 18:57:57'),(53,3,'manual',NULL,'','第五部分单元模块设计\n一、新闻数据采集与数据库支撑设计\n1、新闻数据采集设计\n本项目的数据来源主要包括系统预置数据、RSS新闻爬虫、用户手动输入文本、用户上传文件以及社区用户生成内容，以MySQL业务数据库作为系统运行的主要数据基础。系统围绕新闻浏览、AI标题摘要生成、社区互动、个人中心管理、Timeline事件脉络生成等功能，组织新闻、用户、评论、点赞、收藏、AI生成记录、话题和时间线等数据。\n当前系统采用“数据库优先+Mock兜底”的双轨运行模式。MySQL正常且数据表中存在业务数据时，后端优先读取数据库；当数据库异常、数据不足或局部模块尚未完成真实数据接入时，后端自动回退到backend/app/mock目录中的Mock数据，保证系统演示流程不中断。该设计既符合项目实训阶段的联调需要，也便于后续逐步替换为完全真实的数据驱动模式。\n\n图5-1新闻数据采集与入库流程\n2、新闻数据入库与清洗流程\nRSS新闻采集由scripts/crawlers/rss_news_crawler.py完成。爬虫脚本定时或手动读取RSS源，解析新闻标题、摘要、原文链接、发布时间和来源名称，并进一步访问原文页面提取正文、封面图和更多元信息。系统根据source_url判断新闻是否已入库，避免重复插入；若正文提取失败，则使用RSS摘要作为正文兜底内容。\n新闻入库时，系统会尝试根据分类规则或关键词映射确定category_id，并根据news_topic表中的keyword_list尝试匹配topic_id。若暂时无法匹配到话题，topic_id可以为空，后续由审核/编辑在后台进行手动归类或批量绑定。每次爬虫执行结果写入crawl_log表，用于记录解析数量、新增数量、跳过数量、失败数量和错误信息。\n\n3、数据库文件与初始化协作要求\n项目数据库文件统一放置在database目录下，主要包括schema.sql、seed.sql和migrations目录。其中schema.sql用于创建完整表结构，seed.sql用于导入测试账号、新闻分类、示例新闻、话题和热搜数据，migrations目录用于保存后续新增字段或新增表的迁移脚本。组员首次搭建数据库时，应先执行schema.sql，再执行seed.sql，最后按需要执行migrations脚本。\n\n二、人工智能技术方案\n1、AI微服务技术路线\n本项目的AI能力由独立ai-service提供。ai-service采用FastAPI构建，内部通过OpenAISDK兼容方式调用智谱GLM-4-Flash大模型，同时保留Mock回退机制。后端backend并不直接在业务模块中调用模型，而是通过HTTP/JSON调用ai-service，由ai-service统一完成Prompt构造、模型调用、结果解析和异常兜底。\nai-service的真实目录结构包括routers、schemas、services、mock和core等部分。services目录中的llm_client.py负责大模型客户端调用，prompt_builder.py负责Prompt构造，llm_parser.py负责解析模型返回结果，generate_service.py、extract_service.py、check_service.py、chat_service.py和timeline_service.py分别对应标题摘要生成、新闻要素提取、一致性校验、新闻助手对话和Timeline事件脉络生成。\n\n图5-2AI标题摘要生成调用流程\n2、AI标题摘要生成设计\nAI标题摘要生成是系统的核心功能之一。用户可以在AI生成页面中手动输入新闻正文，也可以从新闻详情页一键导入正文。前端通过frontend/src/api/ai.ts调用后端/api/ai/generate接口，后端modules/ai/service.py对输入文本和生成参数进行校验，然后调用ai-service的generate路由完成标题、摘要、关键词、新闻要素和一致性校验结果生成。\n生成完成后，后端将候选标题、短摘要、长摘要、摘要要点、关键词、新闻要素、风险等级和一致性检查结果写入ai_generate_record表，供个人中心的AI生成历史页面查询和复用。若大模型调用失败，ai-service将回退到mock/sample_outputs.py中的Mock示例输出，从而保证前端页面能够正常展示生成结果。\n\n3、Timeline事件脉络生成设计\nTimeline事件脉络模块用于解决热点事件新闻分散、用户难以把握发展过程的问题。前端通过frontend/src/api/timeline.ts和timeline组件请求后端timeline模块。后端modules/timeline/service.py根据topic_id优先查询event_timeline表中的缓存数据，若缓存不存在或后台触发刷新，则查询news_topic和news表，按publish_time对相关稿件排序，拼接事件上下文后调用ai-service/app/services/timeline_service.py生成结构化时间线节点。\nTimeline模块的核心数据表包括news_topic、news和event_timeline。news_topic保存话题名称、简介和关键词；news表通过topic_id关联话题；event_timeline保存生成后的timeline_json、source_news_ids和生成状态。普通用户主要使用查询接口查看时间线，审核/编辑和管理员可通过后台接口刷新事件脉络、修改单条新闻topic_id或批量归类新闻。\n\n图5-3Timeline事件脉络生成流程\n三、Web端单元UI设计\n本项目采用B/S架构，前端全部基于Vue3、TypeScript、Vite、VueRouter、Pinia、ElementPlus和Axios实现，不包含PyQt桌面端。系统所有功能均通过浏览器访问，前端代码位于frontend/src目录下，页面视图位于views目录，公共组件位于components目录，接口封装位于api目录，状态管理位于stores目录。\n系统页面采用统一MainLayout.vue布局，由顶部导航栏、左侧新闻分类栏和主内容区组成。顶部导航栏包含系统名称、首页、AI生成、社区、个人中心、管理后台、搜索框、明暗模式切换按钮和用户角色标识；左侧分类栏展示推荐、时政、社会、财经、科技、体育、娱乐等新闻分类，并预留生成历史和订阅管理入口。\n\n图5-4Web端单元UI结构\n\n四、后端数据访问封装设计\n1、当前实现结构说明\n本项目采用更符合FastAPI项目实际的轻量化模块结构：每个业务模块位于backend/app/modules目录下，并按照router.py、schema.py、service.py进行组织。其中router.py负责路由定义，schema.py负责Pydantic请求与响应模型，service.py负责业务逻辑处理和数据库访问调用。\n数据库连接与SQL执行统一封装在backend/app/db/database.py中。该文件基于PyMySQL管理MySQL连接，并提供execute_query、execute_one、execute_update等通用方法。各业务模块的service.py调用这些方法完成数据查询、单条查询和写入更新操作。该设计减少了目录复杂度，符合当前项目“数据库优先+Mock兜底”的实际运行方式。\n\n图5-5后端模块与数据库访问封装关系\n\n2、各模块数据访问说明\nauth模块负责登录鉴权，优先读取user表，并兼容mock-token-user、mock-token-editor、mock-token-admin等演示token。user模块负责用户基础信息读取。news模块负责新闻分类、新闻列表、新闻详情和热榜数据查询，主要访问news_category、news、news_topic和hot_topic等表。\ninteraction模块负责点赞、收藏、评论和浏览记录，主要访问news_comment、user_like、favorite和browse_history等表。ai模块负责调用ai-service并将生成结果写入ai_generate_record表。timeline模块负责话题列表、时间线节点和来源新闻关联，主要访问news_topic、news和event_timeline表。community模块负责社区帖子、帖子评论、热搜和拉黑关系，主要访问community_post、post_comment、user_like、favorite、user_block和hot_topic等表。profile模块负责个人中心数据汇总，admin模块负责管理后台内容审核、用户管理、热搜维护、话题归类和系统配置。\n五、业务逻辑层设计\n1、业务模块总体结构\n业务逻辑层是backend服务的核心部分。项目在backend/app/main.py中完成CORS配置、异常处理器注册和9个业务模块路由注册。各模块采用router.py、schema.py、service.py的统一结构，既保证了模块职责清晰，又便于多人并行开发。\n\n2、核心模块详细说明\nauth模块通过user表完成用户名、密码和角色读取，登录成功后返回统一格式的用户信息和token。当前阶段仍兼容Mock登录，便于user、editor、admin三种角色快速演示。router层负责接收登录请求，schema层约束用户名和密码参数，service层完成数据库查询、密码校验和兜底逻辑。\nnews模块负责首页和详情页的数据支撑。首页加载时，news模块读取news_category表返回分类，读取news表返回新闻卡片数据，并结合hot_topic表返回新闻热榜Top10。用户进入新闻详情页时，news或interaction模块会记录browse_history，并更新news.view_count。新闻详情页还可调用AI入口，将当前新闻内容传递给AI生成页面。\ninteraction模块封装点赞、收藏、评论、回复和浏览记录功能。点赞数据写入user_like表，收藏数据写入favorite表，新闻评论写入news_comment表，浏览历史写入browse_history表。由于user_like和favorite均采用target_type+target_id的多态设计，因此同一套表结构可以支持新闻、评论、社区帖子和帖子评论等多种目标。\nai模块是backend与ai-service的桥接模块。前端提交生成请求后，backend/modules/ai/service.py使用httpx调用ai-service。ai-service返回结构化结果后，backend将结果写入ai_generate_record表，并按照统一ApiResponse格式返回前端。该模块保证前端无需关心真实大模型调用细节。\ntimeline模块负责多源事件脉络功能。用户请求某topic_id的时间线时，timeline模块优先读取event_timeline缓存；若缓存不存在，则查询news表中同topic_id的新闻，调用ai-service的timeline_service.py生成时间线，再写回event_timeline表。管理后台可以触发刷新接口，重新生成某个话题的事件脉络。\ncommunity模块负责社区互动业务，包括帖子发布、帖子列表、帖子评论、点赞收藏、用户拉黑和热搜话题展示。profile模块负责个人中心数据聚合，包括浏览历史、收藏记录、评论记录、AI生成历史和分类订阅。admin模块面向审核/编辑和管理员，承担内容审核、用户管理、话题维护、热搜配置和系统管理功能。\n3、RSS爬虫脚本设计\nRSS爬虫脚本位于scripts/crawlers/rss_news_crawler.py，不属于backend/app/modules中的Web路由模块，但它是新闻数据来源的重要组成部分。该脚本支持RSS解析、新闻去重、正文解析、封面图提取、爬虫日志记录和旧新闻归档。执行完成后，新闻数据写入news表，执行日志写入crawl_log表，前端页面即可通过后端新闻接口读取新入库新闻。\n第六部分数据库设计\n一、数据库整体结构\n本项目数据库用于支撑《基于大语言模型的智能新闻摘要与协同互动系统》的核心业务数据存储，包括用户账号、新闻内容、新闻互动、AI生成记录、社区讨论、个人中心、RSS爬虫日志、Timeline事件脉络以及用户分类订阅等模块。数据库采用MySQL8.0，字符集统一使用utf8mb4，排序规则使用utf8mb4_unicode_ci，存储引擎统一采用InnoDB。\n数据库名称建议为llm_news_system。当前系统采用“数据库优先+Mock兜底”的方式运行。MySQL正常时，后端优先读写数据库；当数据库异常或部分模块数据不足时，后端回退到Mock数据，保证系统演示流程不中断。\n\n图6-1数据库核心关系结构图\n\n二、用户与权限管理\n1、user表结构\nuser表用于保存系统用户账号信息，包括普通用户、审核/编辑和管理员。该表是登录认证、权限控制、个人中心、社区发帖、点赞收藏和后台管理的基础表。当前系统优先从user表读取登录用户信息，同时兼容Mocktoken。\n系统预置测试账号包括user/123456、editor/123456和admin/123456，分别对应普通用户、审核/编辑和管理员角色。\n三、新闻内容管理\n1、news_category表结构\nnews_category表用于存储新闻分类信息，支撑首页左侧分类栏、分类筛选和分类高亮功能。系统预置分类包括推荐、时政、社会、财经、科技、体育、娱乐、国际等。\n\n2、news_topic表结构\nnews_topic表用于保存新闻话题，是Timeline事件脉络生成的基础表。一条话题可以关联多篇新闻，新闻通过news.topic_id与该表关联。keyword_list使用JSON格式保存关键词列表，用于自动打标和话题聚合。\n\n3、news表结构\nnews表是系统最核心的数据表，用于保存新闻标题、摘要、正文、封面图、来源、分类、话题、统计量和原文链接等信息。RSS爬虫抓取到的真实新闻最终写入该表。source_url用于新闻去重，topic_id用于Timeline聚合，category_id用于分类筛选。\n\nnews表中不建议直接保存source_name和topic_name。source_name可以由source字段表示，topic_name应通过topic_id关联news_topic表获得。后端接口如需返回这些展示字段，可在查询时通过字段映射或JOIN生成。\n四、新闻互动与个人行为管理\n1、news_comment表结构\nnews_comment表用于保存新闻详情页中的用户评论和回复。通过parent_id实现一级评论和回复评论。\n\n2、user_like表结构\nuser_like是通用点赞表，用于记录用户对新闻、新闻评论、社区帖子和帖子评论等不同目标的点赞行为。该表通过user_id、target_type、target_id组合避免重复点赞。\n\n3、favorite表结构\nfavorite是通用收藏表，用于记录用户收藏新闻、社区帖子或AI记录的行为。该表支撑新闻收藏、社区帖子收藏、个人中心收藏记录和收藏状态判断。\n\n4、browse_history表结构\nbrowse_history表用于记录用户浏览过的新闻。用户打开新闻详情页时，系统写入或更新浏览记录；个人中心的浏览历史页面从该表读取数据。\n\n五、AI生成与文件上传管理\n1、ai_generate_record表结构\nai_generate_record表用于保存用户在AI标题摘要生成页面中的生成历史。用户输入新闻正文或从新闻详情页导入正文后，AI生成的候选标题、摘要、关键词、新闻要素和一致性检查结果会保存到该表中。\n\n2、upload_file表结构\nupload_file表用于保存用户上传文件的基本信息。数据库中只保存文件元数据，实际文件可保存在服务器本地目录或后续对象存储中。\n\n六、社区协同互动管理\n1、community_post表结构\ncommunity_post表用于保存用户在社区页面发布的帖子。帖子可以关联新闻，也可以关联Timeline话题。该表支撑帖子列表、发帖、帖子详情、热度排序和管理后台审核。\n\n2、post_comment表结构\npost_comment表用于保存社区帖子下的评论和回复，通过parent_id支持评论回复结构。\n\n3、user_block表结构\nuser_block表用于保存用户之间的拉黑关系。社区列表加载时，系统可根据当前用户的拉黑记录过滤对应用户发布的帖子和评论。\n\n七、热搜与Timeline管理\n1、hot_topic表结构\nhot_topic表用于保存首页、社区或侧边栏展示的热搜内容。target_type可以指向新闻、新闻话题或社区帖子，用于形成热榜入口和事件脉络入口。\n\n2、event_timeline表结构\nevent_timeline表用于保存某个话题下的事件时间线生成结果，是Timeline模块的缓存表。后端timeline模块优先从该表读取数据；当缓存不存在或后台刷新时，再调用ai-service的timeline_service.py生成新的时间线结果。\n\n八、RSS爬虫与用户订阅管理\n1、crawl_log表结构\ncrawl_log表用于记录RSS新闻爬虫每次执行的结果，由scripts/crawlers/rss_news_crawler.py写入。该表可用于判断爬虫是否正常运行，并为后续管理后台展示爬虫状态提供数据支撑。\n\n2、user_category_subscription表结构\nuser_category_subscription表由migration005创建，用于保存用户订阅的新闻分类，支撑侧边栏订阅管理和后续个性化推荐。\n\n九、主要外键与关系说明\n本项目数据库整体上围绕user、news、news_topic、community_post和ai_generate_record等核心表展开。由于当前阶段仍兼容mock兜底，部分外键可以先采用应用层约束，后续数据库稳定后再逐步增加物理外键约束。\n',3,'generate','简明扼要','客观新闻型','both','[\"基于大语言模型的智能新闻摘要系统：创新设计与实现\", \"深度解析：智能新闻摘要与协同互动系统的数据库设计与AI应用\", \"技术突破：构建高效新闻数据采集与AI摘要生成平台\"]','本项目介绍了一种基于大语言模型的智能新闻摘要与协同互动系统，包括新闻数据采集、数据库设计、AI技术方案、Web端UI设计、后端数据访问封装和业务逻辑层设计等关键环节。','本文详细阐述了基于大语言模型的智能新闻摘要与协同互动系统的设计与实现过程。系统采用MySQL数据库作为数据基础，通过AI技术实现新闻标题摘要生成、Timeline事件脉络生成等功能。同时，系统还涵盖了Web端UI设计、后端数据访问封装和业务逻辑层设计等多个方面，旨在为用户提供高效、便捷的新闻阅读体验。','[\"系统采用MySQL数据库作为数据基础，确保数据存储的稳定性和安全性。\", \"AI技术应用于新闻标题摘要生成和Timeline事件脉络生成，提升用户体验。\", \"系统设计涵盖多个方面，包括Web端UI设计、后端数据访问封装和业务逻辑层设计等，实现高效新闻阅读体验。\"]','[\"智能新闻摘要\", \"协同互动系统\", \"数据库设计\", \"AI技术\", \"Web端UI设计\", \"后端数据访问\", \"业务逻辑层设计\"]','{\"how\": \"采用MySQL数据库、AI技术、Web端UI设计、后端数据访问封装和业务逻辑层设计等手段\", \"who\": \"项目团队\", \"why\": \"提升新闻阅读体验\", \"what\": \"基于大语言模型的智能新闻摘要与协同互动系统\", \"when\": \"当前阶段\", \"where\": \"系统内部\"}','low','{\"score\": 90, \"issues\": [\"部分外键采用应用层约束，后期需逐步增加物理外键约束\"], \"risk_level\": \"low\", \"suggestions\": [\"加强数据库性能优化，提高系统稳定性\"]}','mock',1,'2026-06-29 19:02:06','2026-06-29 19:02:06','2026-06-29 19:02:06','2026-06-29 19:02:06'),(54,3,'manual',NULL,'','亚特兰大后卫帕莱斯特拉飞抵伦敦，体检直接通过！切尔西这笔交易总价超5000万欧元，还加了二次转会分成。罗马诺亲口确认，马上就是‘Here we go’！\n\n国米本来都谈妥了，4500万加500万浮动，12小时前还在开会准备庆祝。结果切尔西半路杀出，直接加价截胡！球员本人放话：两家都行，你们定。亚特兰大一看钞票，果断送他去斯坦福桥。\n\n新帅哈维·阿隆索亲自打电话游说，这小伙子能踢左右两个边翼卫，库库雷利亚走了之后，正好补缺。合同签到2032年，年薪500万欧，第六笔签约基本落袋。\n\n西班牙那边消息更猛，切尔西直接向巴萨报价8000万欧元，折合6900万英镑，要挖中卫库巴西！巴萨秒拒，态度硬得像石头：库巴西、亚马尔、佩德里这批人，全是非卖品，想带走？掏违约金，一个子儿不能少。',5,'generate','简明扼要','客观新闻型','both','[\"切尔西5000万欧元签下帕莱斯特拉，亚特兰大果断放行\", \"帕莱斯特拉体检通过，切尔西截胡国米，签约至2032年\", \"罗马诺确认：帕莱斯特拉加盟切尔西，年薪500万欧元\", \"切尔西报价8000万欧元求购库巴西，巴萨强硬拒绝\", \"亚特兰大后卫帕莱斯特拉飞抵伦敦，体检通过，切尔西交易总价超5000万欧元\"]','切尔西以超过5000万欧元的价格签下亚特兰大后卫帕莱斯特拉，体检通过，合同签到2032年。同时，切尔西向巴萨报价8000万欧元求购库巴西，但被巴萨拒绝。','切尔西成功签下亚特兰大后卫帕莱斯特拉，交易总价超过5000万欧元，体检通过，合同签到2032年，年薪500万欧元。此前，国米曾与帕莱斯特拉达成4500万欧元加500万浮动费用的转会协议，但被切尔西截胡。此外，切尔西还向巴萨报价8000万欧元求购中卫库巴西，但被巴萨强硬拒绝。','[\"切尔西签下帕莱斯特拉，合同签到2032年\", \"切尔西截胡国米，帕莱斯特拉转会费超5000万欧元\", \"切尔西报价8000万欧元求购库巴西，但被巴萨拒绝\"]','[\"切尔西\", \"帕莱斯特拉\", \"亚特兰大\", \"转会\", \"库巴西\", \"巴萨\"]','{\"how\": \"签约、报价\", \"who\": \"切尔西、帕莱斯特拉、亚特兰大、库巴西、巴萨\", \"why\": \"补强阵容、求购球员\", \"what\": \"切尔西签下帕莱斯特拉，报价求购库巴西\", \"when\": \"现在\", \"where\": \"伦敦、亚特兰大、巴萨\"}','low','{\"score\": 85, \"issues\": [\"\"], \"risk_level\": \"low\", \"suggestions\": [\"\"]}','mock',1,'2026-06-30 08:53:13','2026-06-30 08:53:13','2026-06-30 08:53:13','2026-06-30 08:53:13'),(55,3,'manual',NULL,'','亚特兰大后卫帕莱斯特拉飞抵伦敦，体检直接通过！切尔西这笔交易总价超5000万欧元，还加了二次转会分成。罗马诺亲口确认，马上就是‘Here we go’！\n\n国米本来都谈妥了，4500万加500万浮动，12小时前还在开会准备庆祝。结果切尔西半路杀出，直接加价截胡！球员本人放话：两家都行，你们定。亚特兰大一看钞票，果断送他去斯坦福桥。\n\n新帅哈维·阿隆索亲自打电话游说，这小伙子能踢左右两个边翼卫，库库雷利亚走了之后，正好补缺。合同签到2032年，年薪500万欧，第六笔签约基本落袋。\n\n西班牙那边消息更猛，切尔西直接向巴萨报价8000万欧元，折合6900万英镑，要挖中卫库巴西！巴萨秒拒，态度硬得像石头：库巴西、亚马尔、佩德里这批人，全是非卖品，想带走？掏违约金，一个子儿不能少。',3,'generate','简明扼要','客观新闻型','both','[\"切尔西5000万欧元签下亚特兰大后卫，帕莱斯特拉体检通过！\", \"亚特兰大后卫帕莱斯特拉加盟切尔西，新帅哈维亲自游说！\", \"切尔西截胡国米，4500万欧元签下亚特兰大后卫帕莱斯特拉\"]','切尔西以5000万欧元的价格签下亚特兰大后卫帕莱斯特拉，体检通过，合同签到2032年。同时，切尔西向巴萨报价8000万欧元求购中卫库巴西，但被拒绝。','切尔西成功签下亚特兰大后卫帕莱斯特拉，交易总价超过5000万欧元，并包含二次转会分成。帕莱斯特拉体检顺利通过，合同签到2032年，年薪500万欧元。此外，切尔西还向巴萨报价8000万欧元求购中卫库巴西，但被巴萨拒绝，巴萨表示库巴西、亚马尔、佩德里是非卖品。','[\"切尔西签下亚特兰大后卫帕莱斯特拉，合同签到2032年，年薪500万欧元。\", \"切尔西向巴萨报价8000万欧元求购中卫库巴西，但被拒绝。\", \"帕莱斯特拉体检通过，成为切尔西新成员。\"]','[\"切尔西\", \"亚特兰大后卫\", \"帕莱斯特拉\", \"签约\", \"巴萨\", \"库巴西\", \"报价\", \"拒绝\"]','{\"how\": \"签约、报价\", \"who\": \"切尔西、亚特兰大后卫帕莱斯特拉、巴萨、库巴西\", \"why\": \"补强阵容、求购球员\", \"what\": \"切尔西签下帕莱斯特拉，向巴萨报价库巴西\", \"when\": \"现在\", \"where\": \"伦敦、亚特兰大、巴萨\"}','low','{\"score\": 85, \"issues\": [\"\"], \"risk_level\": \"low\", \"suggestions\": [\"\"]}','mock',1,'2026-06-30 08:53:51','2026-06-30 08:53:51','2026-06-30 08:53:51','2026-06-30 08:53:51'),(56,3,'manual',NULL,'','直播吧06月29日讯 在曼城官宣马雷斯卡出任主帅后，切尔西发布声明，矛头直指马雷斯卡，称马雷斯卡早就希望去曼城，因而主动辞职，他与曼城将支付赔偿金。\n\n据BBC此前报道，曼城和切尔西一直在就赔偿金进行谈判，了解到赔偿金额超过了1000万英镑。切尔西认为根据马雷斯卡离开时的合同条款，他们有权获得赔偿。这位意大利教练原本与切尔西的合同到2029年，但他在一月份离开了球队，蓝军一直在探索法律途径。\n\n泰晤士报也表示，在与切尔西就超过1000万镑的赔偿方案达成协议后，马雷斯卡已同意签署一份为期三年的合同，出任曼城主教练。曼城将马雷斯卡选为接替瓜迪奥拉的首选。',3,'generate','简明扼要','客观新闻型','both','[\"切尔西主帅马雷斯卡加盟曼城，赔偿金超千万英镑\", \"曼城官宣马雷斯卡接替瓜迪奥拉，切尔西要求赔偿\", \"马雷斯卡与切尔西合同纠纷，加盟曼城赔偿金达千万级\"]','意大利教练马雷斯卡从切尔西辞职，加盟曼城成为新任主教练。双方就赔偿金达成协议，金额超过1000万英镑。','切尔西主帅马雷斯卡在官宣加盟曼城后，切尔西发布声明称马雷斯卡主动辞职，并要求支付赔偿金。据了解，赔偿金超过1000万英镑。马雷斯卡原本与切尔西的合同到2029年，但他在一月份离开了球队。曼城与切尔西就赔偿金达成协议后，马雷斯卡已同意签署一份为期三年的合同，成为曼城的新任主教练。','[\"马雷斯卡从切尔西辞职并加盟曼城\", \"赔偿金超过1000万英镑\", \"马雷斯卡与切尔西合同纠纷\"]','[\"马雷斯卡\", \"切尔西\", \"曼城\", \"赔偿金\", \"教练\", \"转会\"]','{\"how\": \"通过赔偿金谈判达成协议\", \"who\": \"马雷斯卡、切尔西、曼城\", \"why\": \"马雷斯卡希望加盟曼城，赔偿金问题\", \"what\": \"马雷斯卡加盟曼城，切尔西要求赔偿\", \"when\": \"2023年6月29日\", \"where\": \"曼城、切尔西\"}','low','{\"score\": 85, \"issues\": [\"赔偿金具体金额未明确\"], \"risk_level\": \"low\", \"suggestions\": [\"补充赔偿金具体金额\"]}','mock',1,'2026-06-30 09:29:32','2026-06-30 09:29:32','2026-06-30 09:29:32','2026-06-30 09:29:32'),(59,3,'manual',NULL,'','第五部分单元模块设计\n一、新闻数据采集与数据库支撑设计\n1、新闻数据采集设计\n本项目的数据来源主要包括系统预置数据、RSS新闻爬虫、用户手动输入文本、用户上传文件以及社区用户生成内容，以MySQL业务数据库作为系统运行的主要数据基础。系统围绕新闻浏览、AI标题摘要生成、社区互动、个人中心管理、Timeline事件脉络生成等功能，组织新闻、用户、评论、点赞、收藏、AI生成记录、话题和时间线等数据。\n当前系统采用“数据库优先+Mock兜底”的双轨运行模式。MySQL正常且数据表中存在业务数据时，后端优先读取数据库；当数据库异常、数据不足或局部模块尚未完成真实数据接入时，后端自动回退到backend/app/mock目录中的Mock数据，保证系统演示流程不中断。该设计既符合项目实训阶段的联调需要，也便于后续逐步替换为完全真实的数据驱动模式。\n\n图5-1新闻数据采集与入库流程\n2、新闻数据入库与清洗流程\nRSS新闻采集由scripts/crawlers/rss_news_crawler.py完成。爬虫脚本定时或手动读取RSS源，解析新闻标题、摘要、原文链接、发布时间和来源名称，并进一步访问原文页面提取正文、封面图和更多元信息。系统根据source_url判断新闻是否已入库，避免重复插入；若正文提取失败，则使用RSS摘要作为正文兜底内容。\n新闻入库时，系统会尝试根据分类规则或关键词映射确定category_id，并根据news_topic表中的keyword_list尝试匹配topic_id。若暂时无法匹配到话题，topic_id可以为空，后续由审核/编辑在后台进行手动归类或批量绑定。每次爬虫执行结果写入crawl_log表，用于记录解析数量、新增数量、跳过数量、失败数量和错误信息。\n\n3、数据库文件与初始化协作要求\n项目数据库文件统一放置在database目录下，主要包括schema.sql、seed.sql和migrations目录。其中schema.sql用于创建完整表结构，seed.sql用于导入测试账号、新闻分类、示例新闻、话题和热搜数据，migrations目录用于保存后续新增字段或新增表的迁移脚本。组员首次搭建数据库时，应先执行schema.sql，再执行seed.sql，最后按需要执行migrations脚本。\n\n二、人工智能技术方案\n1、AI微服务技术路线\n本项目的AI能力由独立ai-service提供。ai-service采用FastAPI构建，内部通过OpenAISDK兼容方式调用智谱GLM-4-Flash大模型，同时保留Mock回退机制。后端backend并不直接在业务模块中调用模型，而是通过HTTP/JSON调用ai-service，由ai-service统一完成Prompt构造、模型调用、结果解析和异常兜底。\nai-service的真实目录结构包括routers、schemas、services、mock和core等部分。services目录中的llm_client.py负责大模型客户端调用，prompt_builder.py负责Prompt构造，llm_parser.py负责解析模型返回结果，generate_service.py、extract_service.py、check_service.py、chat_service.py和timeline_service.py分别对应标题摘要生成、新闻要素提取、一致性校验、新闻助手对话和Timeline事件脉络生成。\n\n图5-2AI标题摘要生成调用流程\n2、AI标题摘要生成设计\nAI标题摘要生成是系统的核心功能之一。用户可以在AI生成页面中手动输入新闻正文，也可以从新闻详情页一键导入正文。前端通过frontend/src/api/ai.ts调用后端/api/ai/generate接口，后端modules/ai/service.py对输入文本和生成参数进行校验，然后调用ai-service的generate路由完成标题、摘要、关键词、新闻要素和一致性校验结果生成。\n生成完成后，后端将候选标题、短摘要、长摘要、摘要要点、关键词、新闻要素、风险等级和一致性检查结果写入ai_generate_record表，供个人中心的AI生成历史页面查询和复用。若大模型调用失败，ai-service将回退到mock/sample_outputs.py中的Mock示例输出，从而保证前端页面能够正常展示生成结果。\n\n3、Timeline事件脉络生成设计\nTimeline事件脉络模块用于解决热点事件新闻分散、用户难以把握发展过程的问题。前端通过frontend/src/api/timeline.ts和timeline组件请求后端timeline模块。后端modules/timeline/service.py根据topic_id优先查询event_timeline表中的缓存数据，若缓存不存在或后台触发刷新，则查询news_topic和news表，按publish_time对相关稿件排序，拼接事件上下文后调用ai-service/app/services/timeline_service.py生成结构化时间线节点。\nTimeline模块的核心数据表包括news_topic、news和event_timeline。news_topic保存话题名称、简介和关键词；news表通过topic_id关联话题；event_timeline保存生成后的timeline_json、source_news_ids和生成状态。普通用户主要使用查询接口查看时间线，审核/编辑和管理员可通过后台接口刷新事件脉络、修改单条新闻topic_id或批量归类新闻。\n\n图5-3Timeline事件脉络生成流程\n三、Web端单元UI设计\n本项目采用B/S架构，前端全部基于Vue3、TypeScript、Vite、VueRouter、Pinia、ElementPlus和Axios实现，不包含PyQt桌面端。系统所有功能均通过浏览器访问，前端代码位于frontend/src目录下，页面视图位于views目录，公共组件位于components目录，接口封装位于api目录，状态管理位于stores目录。\n系统页面采用统一MainLayout.vue布局，由顶部导航栏、左侧新闻分类栏和主内容区组成。顶部导航栏包含系统名称、首页、AI生成、社区、个人中心、管理后台、搜索框、明暗模式切换按钮和用户角色标识；左侧分类栏展示推荐、时政、社会、财经、科技、体育、娱乐等新闻分类，并预留生成历史和订阅管理入口。\n\n图5-4Web端单元UI结构\n\n四、后端数据访问封装设计\n1、当前实现结构说明\n本项目采用更符合FastAPI项目实际的轻量化模块结构：每个业务模块位于backend/app/modules目录下，并按照router.py、schema.py、service.py进行组织。其中router.py负责路由定义，schema.py负责Pydantic请求与响应模型，service.py负责业务逻辑处理和数据库访问调用。\n数据库连接与SQL执行统一封装在backend/app/db/database.py中。该文件基于PyMySQL管理MySQL连接，并提供execute_query、execute_one、execute_update等通用方法。各业务模块的service.py调用这些方法完成数据查询、单条查询和写入更新操作。该设计减少了目录复杂度，符合当前项目“数据库优先+Mock兜底”的实际运行方式。\n\n图5-5后端模块与数据库访问封装关系\n\n2、各模块数据访问说明\nauth模块负责登录鉴权，优先读取user表，并兼容mock-token-user、mock-token-editor、mock-token-admin等演示token。user模块负责用户基础信息读取。news模块负责新闻分类、新闻列表、新闻详情和热榜数据查询，主要访问news_category、news、news_topic和hot_topic等表。\ninteraction模块负责点赞、收藏、评论和浏览记录，主要访问news_comment、user_like、favorite和browse_history等表。ai模块负责调用ai-service并将生成结果写入ai_generate_record表。timeline模块负责话题列表、时间线节点和来源新闻关联，主要访问news_topic、news和event_timeline表。community模块负责社区帖子、帖子评论、热搜和拉黑关系，主要访问community_post、post_comment、user_like、favorite、user_block和hot_topic等表。profile模块负责个人中心数据汇总，admin模块负责管理后台内容审核、用户管理、热搜维护、话题归类和系统配置。\n五、业务逻辑层设计\n1、业务模块总体结构\n业务逻辑层是backend服务的核心部分。项目在backend/app/main.py中完成CORS配置、异常处理器注册和9个业务模块路由注册。各模块采用router.py、schema.py、service.py的统一结构，既保证了模块职责清晰，又便于多人并行开发。\n\n2、核心模块详细说明\nauth模块通过user表完成用户名、密码和角色读取，登录成功后返回统一格式的用户信息和token。当前阶段仍兼容Mock登录，便于user、editor、admin三种角色快速演示。router层负责接收登录请求，schema层约束用户名和密码参数，service层完成数据库查询、密码校验和兜底逻辑。\nnews模块负责首页和详情页的数据支撑。首页加载时，news模块读取news_category表返回分类，读取news表返回新闻卡片数据，并结合hot_topic表返回新闻热榜Top10。用户进入新闻详情页时，news或interaction模块会记录browse_history，并更新news.view_count。新闻详情页还可调用AI入口，将当前新闻内容传递给AI生成页面。\ninteraction模块封装点赞、收藏、评论、回复和浏览记录功能。点赞数据写入user_like表，收藏数据写入favorite表，新闻评论写入news_comment表，浏览历史写入browse_history表。由于user_like和favorite均采用target_type+target_id的多态设计，因此同一套表结构可以支持新闻、评论、社区帖子和帖子评论等多种目标。\nai模块是backend与ai-service的桥接模块。前端提交生成请求后，backend/modules/ai/service.py使用httpx调用ai-service。ai-service返回结构化结果后，backend将结果写入ai_generate_record表，并按照统一ApiResponse格式返回前端。该模块保证前端无需关心真实大模型调用细节。\ntimeline模块负责多源事件脉络功能。用户请求某topic_id的时间线时，timeline模块优先读取event_timeline缓存；若缓存不存在，则查询news表中同topic_id的新闻，调用ai-service的timeline_service.py生成时间线，再写回event_timeline表。管理后台可以触发刷新接口，重新生成某个话题的事件脉络。\ncommunity模块负责社区互动业务，包括帖子发布、帖子列表、帖子评论、点赞收藏、用户拉黑和热搜话题展示。profile模块负责个人中心数据聚合，包括浏览历史、收藏记录、评论记录、AI生成历史和分类订阅。admin模块面向审核/编辑和管理员，承担内容审核、用户管理、话题维护、热搜配置和系统管理功能。\n3、RSS爬虫脚本设计\nRSS爬虫脚本位于scripts/crawlers/rss_news_crawler.py，不属于backend/app/modules中的Web路由模块，但它是新闻数据来源的重要组成部分。该脚本支持RSS解析、新闻去重、正文解析、封面图提取、爬虫日志记录和旧新闻归档。执行完成后，新闻数据写入news表，执行日志写入crawl_log表，前端页面即可通过后端新闻接口读取新入库新闻。\n第六部分数据库设计\n一、数据库整体结构\n本项目数据库用于支撑《基于大语言模型的智能新闻摘要与协同互动系统》的核心业务数据存储，包括用户账号、新闻内容、新闻互动、AI生成记录、社区讨论、个人中心、RSS爬虫日志、Timeline事件脉络以及用户分类订阅等模块。数据库采用MySQL8.0，字符集统一使用utf8mb4，排序规则使用utf8mb4_unicode_ci，存储引擎统一采用InnoDB。\n数据库名称建议为llm_news_system。当前系统采用“数据库优先+Mock兜底”的方式运行。MySQL正常时，后端优先读写数据库；当数据库异常或部分模块数据不足时，后端回退到Mock数据，保证系统演示流程不中断。\n\n图6-1数据库核心关系结构图\n\n二、用户与权限管理\n1、user表结构\nuser表用于保存系统用户账号信息，包括普通用户、审核/编辑和管理员。该表是登录认证、权限控制、个人中心、社区发帖、点赞收藏和后台管理的基础表。当前系统优先从user表读取登录用户信息，同时兼容Mocktoken。\n系统预置测试账号包括user/123456、editor/123456和admin/123456，分别对应普通用户、审核/编辑和管理员角色。\n三、新闻内容管理\n1、news_category表结构\nnews_category表用于存储新闻分类信息，支撑首页左侧分类栏、分类筛选和分类高亮功能。系统预置分类包括推荐、时政、社会、财经、科技、体育、娱乐、国际等。\n\n2、news_topic表结构\nnews_topic表用于保存新闻话题，是Timeline事件脉络生成的基础表。一条话题可以关联多篇新闻，新闻通过news.topic_id与该表关联。keyword_list使用JSON格式保存关键词列表，用于自动打标和话题聚合。\n\n3、news表结构\nnews表是系统最核心的数据表，用于保存新闻标题、摘要、正文、封面图、来源、分类、话题、统计量和原文链接等信息。RSS爬虫抓取到的真实新闻最终写入该表。source_url用于新闻去重，topic_id用于Timeline聚合，category_id用于分类筛选。\n\nnews表中不建议直接保存source_name和topic_name。source_name可以由source字段表示，topic_name应通过topic_id关联news_topic表获得。后端接口如需返回这些展示字段，可在查询时通过字段映射或JOIN生成。\n四、新闻互动与个人行为管理\n1、news_comment表结构\nnews_comment表用于保存新闻详情页中的用户评论和回复。通过parent_id实现一级评论和回复评论。\n\n2、user_like表结构\nuser_like是通用点赞表，用于记录用户对新闻、新闻评论、社区帖子和帖子评论等不同目标的点赞行为。该表通过user_id、target_type、target_id组合避免重复点赞。\n\n3、favorite表结构\nfavorite是通用收藏表，用于记录用户收藏新闻、社区帖子或AI记录的行为。该表支撑新闻收藏、社区帖子收藏、个人中心收藏记录和收藏状态判断。\n\n4、browse_history表结构\nbrowse_history表用于记录用户浏览过的新闻。用户打开新闻详情页时，系统写入或更新浏览记录；个人中心的浏览历史页面从该表读取数据。\n\n五、AI生成与文件上传管理\n1、ai_generate_record表结构\nai_generate_record表用于保存用户在AI标题摘要生成页面中的生成历史。用户输入新闻正文或从新闻详情页导入正文后，AI生成的候选标题、摘要、关键词、新闻要素和一致性检查结果会保存到该表中。\n\n2、upload_file表结构\nupload_file表用于保存用户上传文件的基本信息。数据库中只保存文件元数据，实际文件可保存在服务器本地目录或后续对象存储中。\n\n六、社区协同互动管理\n1、community_post表结构\ncommunity_post表用于保存用户在社区页面发布的帖子。帖子可以关联新闻，也可以关联Timeline话题。该表支撑帖子列表、发帖、帖子详情、热度排序和管理后台审核。\n\n2、post_comment表结构\npost_comment表用于保存社区帖子下的评论和回复，通过parent_id支持评论回复结构。\n\n3、user_block表结构\nuser_block表用于保存用户之间的拉黑关系。社区列表加载时，系统可根据当前用户的拉黑记录过滤对应用户发布的帖子和评论。\n\n七、热搜与Timeline管理\n1、hot_topic表结构\nhot_topic表用于保存首页、社区或侧边栏展示的热搜内容。target_type可以指向新闻、新闻话题或社区帖子，用于形成热榜入口和事件脉络入口。\n\n2、event_timeline表结构\nevent_timeline表用于保存某个话题下的事件时间线生成结果，是Timeline模块的缓存表。后端timeline模块优先从该表读取数据；当缓存不存在或后台刷新时，再调用ai-service的timeline_service.py生成新的时间线结果。\n\n八、RSS爬虫与用户订阅管理\n1、crawl_log表结构\ncrawl_log表用于记录RSS新闻爬虫每次执行的结果，由scripts/crawlers/rss_news_crawler.py写入。该表可用于判断爬虫是否正常运行，并为后续管理后台展示爬虫状态提供数据支撑。\n\n2、user_category_subscription表结构\nuser_category_subscription表由migration005创建，用于保存用户订阅的新闻分类，支撑侧边栏订阅管理和后续个性化推荐。\n\n九、主要外键与关系说明\n本项目数据库整体上围绕user、news、news_topic、community_post和ai_generate_record等核心表展开。由于当前阶段仍兼容mock兜底，部分外键可以先采用应用层约束，后续数据库稳定后再逐步增加物理外键约束。\n',3,'generate','简明扼要','客观新闻型','long','[\"智能新闻摘要系统：AI赋能新闻采集与处理\", \"基于大语言模型的新闻摘要与互动系统设计解析\", \"新闻数据采集与AI技术融合：构建智能新闻平台\"]','','本项目详细阐述了基于大语言模型的智能新闻摘要与协同互动系统的设计与实现。系统通过整合新闻数据采集、AI标题摘要生成、Timeline事件脉络生成等功能，实现了新闻处理的高效性和用户体验的优化。系统采用MySQL数据库作为数据基础，结合AI技术实现新闻的自动摘要和事件脉络生成，为用户提供便捷的新闻阅读体验。','[\"新闻数据采集与处理\", \"AI标题摘要生成\", \"Timeline事件脉络生成\", \"MySQL数据库支持\", \"AI技术应用\"]','[\"智能新闻摘要\", \"AI技术\", \"新闻处理\", \"数据库\", \"Timeline事件脉络\"]','{\"how\": \"整合新闻数据采集、AI标题摘要生成、Timeline事件脉络生成等功能\", \"who\": \"本项目团队\", \"why\": \"提升新闻处理效率和用户体验\", \"what\": \"基于大语言模型的智能新闻摘要与协同互动系统\", \"when\": \"当前\", \"where\": \"全球\"}','low','{\"score\": 90, \"issues\": [\"无\"], \"risk_level\": \"low\", \"suggestions\": [\"无\"]}','mock',1,'2026-06-30 10:23:37','2026-06-30 10:23:37','2026-06-30 10:23:37','2026-06-30 10:23:37'),(60,3,'manual',NULL,'','直播吧06月30日讯 近日，西班牙国脚，皇马新援库库雷利亚接受了西班牙六台的快问快答采访。\n\n在社交软件上，什么事情最让你抓狂？是六分钟的长语音，被已读不回，还是对方只回复“哈哈哈”？\n\n“六分钟的长语音。”\n\n如果你在荒岛上搁浅，你会选择哪个国家队队友陪你？\n\n“六分钟语音的那位。”\n\n你相信有外星生命吗？\n\n“我相信有生命。”\n\n那你觉得他们长什么样？\n\n“比我们聪明得多。”\n\n你买过最荒谬的东西是什么？\n\n“一条 WWE（美国职业摔角）的冠军金腰带。”\n\n你手机里最出名的人的联系方式是谁？\n\n“蒂亚戈·席尔瓦。”\n\n你最喜欢的电影是哪部？\n\n“《守法公民》或者《美丽人生》。”\n\n谁曾经是、或者现在是你的偶像？\n\n“罗纳尔迪尼奥”\n\n隐形能力和瞬间移动能力，你选哪一个？\n\n“瞬间移动。”\n\n如果你能给10年前的库库雷利亚发一条信息，你会对他说什么？\n\n“……（思考）最终你做到了。”\n\n明天醒来，你必须在以下两件事里二选一：要么变成一个彻底的秃头，要么在胸口纹一个巴塞罗那队的队徽。你选哪个？\n\n“变成秃头。”',3,'generate','简明扼要','客观新闻型','both','[\"皇马新援库库雷利亚西班牙六台快问快答，分享个人趣事\", \"库库雷利亚谈荒岛队友：六分钟长语音那位\", \"库库雷利亚透露偶像罗纳尔迪尼奥，选瞬间移动能力\"]','皇马新援库库雷利亚近日接受了西班牙六台的快问快答采访，分享了自己的趣事和观点。','近日，西班牙国脚、皇马新援库库雷利亚接受了西班牙六台的快问快答采访。在采访中，库库雷利亚分享了自己在社交软件上的抓狂经历、荒岛上的理想队友、对外星生命的看法、购买过的荒谬物品、最喜欢的电影、偶像以及他选择的超能力等个人趣事和观点。','[\"皇马新援库库雷利亚接受快问快答采访\", \"分享个人趣事和观点\", \"透露偶像罗纳尔迪尼奥，选择瞬间移动能力\"]','[\"库库雷利亚\", \"皇马\", \"快问快答\", \"个人趣事\", \"偶像\", \"瞬间移动\"]','{\"how\": \"快问快答形式\", \"who\": \"皇马新援库库雷利亚\", \"why\": \"分享个人趣事和观点\", \"what\": \"接受西班牙六台的快问快答采访\", \"when\": \"近日\", \"where\": \"西班牙六台\"}','low','{\"score\": 85, \"issues\": [\"无\"], \"risk_level\": \"low\", \"suggestions\": [\"无\"]}','llm',1,'2026-06-30 19:51:55','2026-06-30 19:51:55','2026-06-30 19:51:55','2026-06-30 19:51:55'),(61,3,'manual',NULL,'','AI技术存在感弱：给LLM加了⼀个⽹⻚\n简单流程：⽤户问题 -> LLM API -> 返回⽂本；只是AI⼩助⼿(侧边栏)\n思考流程：⽤户问题 -> 输⼊理解 -> 任务分类/意图识别 -> 数据检索/模型处理 -> 结果校验 -> 结果⽣成 -> 质\n量评估或反馈.......\n2、Coding Agent⽣成项⽬，没有真正设计业务\n⼀次性⽣成：前端 & 后端 & AI & 数据库 & ⽤例。。。。。。\n需要思考：真实数据流、⽤户数据保存、继续挖掘⽤户数据 .......\n3、没有从⽤户使⽤产品⻆度：只考虑功能有没有，不考虑是否需要\n上传⽂档没有进度 & 不显示⽀持什么格式 & 允许多⼤。。。。。。\n⽤户提交任务是否可以取消 & LLM返回结果过⻓，分段 & ⻚⾯显示有价值提示.....\n⽤户输⼊错误 & 重来\n界⾯包含技术术语 。。。。\n4、业务场景不具体，项⽬看起来太空\n业务场景：学校、医院、软件公司、制作企业.......\n解决问题：报销咨询、⼊职培训 ........\n5、管理员端缺失或过于简单\n系统数量与趋势：新增⽤户 & 活跃⽤户 & 任务总数& 上传数量 & 平均处理时间 & ⽤户反馈 & 预测趋势\nAI系统运⾏情况：模型调⽤次数 & 模型响应时间 & 低评分回答数量。。。。。\n异常和⻛险：任务解析失败 & 上传失败 & 敏感内容 & ⻓时间未完成任务 & ⽤户系统反馈  --> 处理\n6、系统可扩展性不⾜(通⽤项⽬)\n⻆⾊固定，⽆法新增其他⻆⾊\n模板固定：⽆法新增“学术摘要、政务摘要、视频⼝播摘要”。。。。。\n知识库类别固定：管理员⽆法新增或修改\n业务流程固定：⽆法根据⽤户⻆⾊ & 任务类型  --> 动态处理业',3,'generate','简明扼要','客观新闻型','both','[\"AI技术发展受限：页面辅助功能弱化用户体验\", \"LLM应用问题凸显：功能缺失与业务场景不匹配\", \"AI系统缺陷分析：扩展性与管理端功能待完善\"]','近期AI技术在应用中暴露出多方面问题，包括页面辅助功能弱化、功能缺失与业务场景不匹配，以及系统扩展性与管理端功能不足。','近期，AI技术在应用中暴露出多方面问题。首先，页面辅助功能弱化，导致用户体验不佳；其次，功能缺失与业务场景不匹配，影响了实际应用效果；最后，系统扩展性与管理端功能不足，限制了AI技术的进一步发展。','[\"页面辅助功能弱化，用户体验不佳\", \"功能缺失与业务场景不匹配，影响应用效果\", \"系统扩展性与管理端功能不足，限制技术发展\"]','[\"AI技术\", \"页面辅助\", \"用户体验\", \"功能缺失\", \"业务场景\", \"系统扩展\", \"管理端功能\"]','{\"how\": \"通过页面辅助功能、功能匹配、系统扩展与管理端功能等方面\", \"who\": \"AI技术\", \"why\": \"技术发展受限\", \"what\": \"页面辅助功能弱化、功能缺失与业务场景不匹配，系统扩展性与管理端功能不足\", \"when\": \"近期\", \"where\": \"AI技术应用领域\"}','medium','{\"score\": 85, \"issues\": [\"功能缺失与业务场景不匹配可能导致实际应用效果不佳\"], \"risk_level\": \"medium\", \"suggestions\": [\"加强页面辅助功能，提高用户体验；优化功能匹配，满足业务场景需求；提升系统扩展性与管理端功能\"]}','llm',1,'2026-07-01 12:55:15','2026-07-01 12:55:15','2026-07-01 12:55:15','2026-07-01 12:55:15');
