INSERT INTO `community_post` VALUES (1,1,'大家平时会先看 AI 摘要还是直接读全文？','最近新闻详情页已经可以跳转到 AI 标题摘要生成页，我试了一下，长新闻先看摘要确实更容易判断是否值得阅读全文。想和大家讨论一下：如果是科技、财经这类信息密度高的新闻，你们更希望摘要偏短、更客观，还是希望同时给出背景和后续影响？',1,1,'[\"AI摘要\", \"阅读效率\", \"新闻详情\"]',8,3,4,0,98,1,'2026-06-27 11:54:22','2026-07-01 11:09:17','2026-06-20 09:15:00','2026-07-01 11:09:17'),(2,2,'低空经济新闻适合做事件脉络吗？','低空经济相关报道往往涉及政策、产业园、无人机应用和安全规范。单篇新闻能提供一个角度，但如果能把同一话题下的报道按时间线串起来，应该更容易看清产业发展节奏。大家觉得事件脉络里最重要的是时间节点、来源新闻，还是节点摘要？',2,2,'[\"低空经济\", \"事件脉络\", \"无人机\"]',12,14,3,6,131,1,'2026-06-27 11:54:22','2026-07-01 13:13:17','2026-06-20 11:30:00','2026-07-01 13:13:17'),(3,3,'新能源汽车和智能交通的数据怎么展示更直观？','新能源汽车相关信息包含销量、充电设施、智能驾驶、城市交通等维度。如果后续个人中心能把用户阅读过的新能源新闻聚合成阅读脉络，可能可以帮助用户发现自己长期关注的话题。欢迎补充你们觉得适合可视化的字段。',3,3,'[\"新能源汽车\", \"智能交通\", \"数据可视化\"]',10,2,3,0,106,1,'2026-06-27 11:54:22','2026-07-01 11:09:16','2026-06-21 14:20:00','2026-07-01 11:09:16'),(4,1,'社区讨论区可以增加哪些新闻互动入口？','现在社区页已经有帖子列表、热搜话题和互动按钮。如果从新闻详情页进入社区讨论，最好能自动关联原新闻，并把标题、来源展示出来，这样讨论不会脱离新闻语境。这个帖子主要用来测试社区数据库数据展示和评论回复功能。',4,1,'[\"社区互动\", \"关联新闻\", \"功能测试\"]',6,2,1,0,91,1,'2026-06-27 11:54:22','2026-07-01 11:00:43','2026-06-22 08:45:00','2026-07-01 11:00:43'),(5,2,'编辑视角：评论审核应该保留哪些状态？','评论数据里已经有正常、折叠、待审核和删除等状态。为了演示后台审核能力，建议社区评论和新闻评论都保留状态字段，并在页面上区分正常展示和折叠展示。后续如果接入真实审核流程，也更容易扩展。',5,1,'[\"评论审核\", \"后台管理\", \"数据状态\"]',5,1,1,1,76,1,'2026-06-27 11:54:22','2026-07-01 10:34:13','2026-06-22 16:10:00','2026-07-01 10:34:13'),(6,1,'待审核演示帖：社区内容审核流程测试','这是一条用于管理后台待审核列表演示的帖子。普通社区列表不应展示，管理员后台或编辑后台可以读取到该状态，用于测试审核、筛选和后续管理流程。',6,2,'[\"待审核\", \"管理后台\", \"演示数据\"]',0,0,0,0,20,3,'2026-06-27 11:54:22','2026-06-23 10:00:00','2026-06-23 10:00:00','2026-06-29 17:17:52'),(26,3,'111','22222',NULL,NULL,'[]',0,18,0,7,18,1,'2026-06-29 09:33:08','2026-07-01 09:52:41','2026-06-29 09:33:08','2026-07-01 09:52:41'),(27,3,'1','2',NULL,NULL,'[\"军事\", \"健康\", \"娱乐\", \"国际\"]',0,4,0,3,4,1,'2026-06-29 17:35:53','2026-07-01 10:24:28','2026-06-29 17:35:53','2026-07-01 10:24:28'),(28,3,'12','2',NULL,NULL,'[\"健康\", \"军事\"]',0,8,1,5,8,1,'2026-06-30 10:28:07','2026-07-01 11:25:31','2026-06-30 10:28:07','2026-07-01 11:25:31');
