INSERT INTO `news` VALUES (1,'人工智能技术加速落地，多行业探索智能化转型','人工智能技术正在从模型能力展示走向产业应用，多个行业开始探索智能化升级路径。','近年来，人工智能技术快速发展，大模型、智能问答、内容生成和数据分析等能力逐渐进入实际业务场景。在新闻、教育、医疗、制造和交通等领域，相关企业和机构正在探索如何利用人工智能提高效率、降低成本并改善用户体验。业内人士认为，随着基础设施、算法能力和应用生态不断完善，人工智能将进一步推动各行业数字化转型。','',5,1,'系统示例数据','','2026-01-01 09:00:00','https://example.com/news/ai-1',130,8,5,5,'[\"人工智能\", \"大模型\", \"产业应用\"]',1,'2026-06-27 11:40:43','2026-07-01 11:01:05','2026-06-27 11:40:43','2026-07-01 11:01:05'),(2,'低空经济发展提速，无人机应用场景不断拓展','低空经济成为新兴产业关注点，无人机物流、巡检、测绘等应用不断扩展。','随着相关政策和基础设施不断完善，低空经济正在成为多个地区培育新质生产力的重要方向。无人机在物流配送、农业植保、应急救援、电力巡检和城市治理等场景中展现出较强应用价值。专家表示，低空经济的发展需要统筹空域管理、飞行安全、产业标准和商业模式创新。','',5,2,'系统示例数据','','2026-01-02 10:00:00','https://example.com/news/drone-1',96,6,1,3,'[\"低空经济\", \"无人机\", \"产业发展\"]',1,'2026-06-27 11:40:43','2026-06-27 11:56:18','2026-06-27 11:40:43','2026-06-27 11:56:18'),(3,'新能源汽车市场持续增长，智能交通生态加快形成','新能源汽车销量增长带动充电、智能驾驶和交通服务生态持续完善。','新能源汽车产业近年来保持较快发展，带动动力电池、充电基础设施、智能驾驶和车联网等相关产业协同升级。随着车辆智能化水平提升，交通管理、能源补给和出行服务也在发生变化。业内认为，新能源汽车与智能交通的结合将推动城市交通系统更加高效和低碳。','',4,3,'系统示例数据','','2026-01-03 11:00:00','https://example.com/news/ev-1',90,5,1,2,'[\"新能源汽车\", \"智能交通\", \"低碳出行\"]',1,'2026-06-27 11:40:43','2026-06-29 17:21:13','2026-06-27 11:40:43','2026-06-29 17:21:13'),(624,'国家税务总局深圳市税务局党委委员吴德接受审查调查','中新网6月27日电 据中央纪委国家监委驻国家税务总局纪检监察组、广东省纪委监委消息：国家税务总局深圳市税务局党委委员、副局长吴德涉嫌严重违纪违法，目前正接受中央纪委国家监委驻国家税务总局纪检监察组纪律审查和广东省湛江市监察委员会监察调查。','中新网 6月27日电 据中央纪委国家监委驻国家税务总局纪检监察组、广东省纪委监委消息：国家税务总局深圳市税务局党委委员、副局长吴德涉嫌严重违纪违法，目前正接受中央纪委国家监委驻国家税务总局纪检监察组纪律审查和广东省湛江市监察委员会监察调查。\n\n董勇《繁花》的遗憾在《太平年》补上了\n\n首获白玉兰最佳女演员！杨紫想夸夸自己\n\n从传统人防到数智赋能 江西婺源宋代廊桥焕发新活力\n\n《沉默的荣耀》原型朱枫外孙女：外婆 您看到了吗？\n\n移民管理警察上勤队列 吸引中外旅客拍照点赞\n\n云南普洱集中公开销毁5.5吨毒品\n\n“世界海拔最高的千人那曲锅庄”世界纪录诞生\n\n石家庄“国字脸”网红小猴正式定名“石英俊”\n\n跨省运输活鸭“中暑” 消防水枪紧急喷淋降温\n\n幼儿园举行自理能力大赛 淡定小孩哥不慌不忙\n\n2034年能踢进世界杯吗？中国足球小将“空翻哥”的回答很棒\n\n南博会上挑战“见手青拿铁” 喝完会不会看见“小人人”\n\n河北农业大学毕业典礼上 学生轮番整活把校长“忙坏了”\n\n津台萌娃一逗一捧：“咱说的都是中国话”\n\n女子穿旗袍配高跟鞋跳绳惊艳网友\n\n登贝莱半场“戴帽” 法国队4比1战胜挪威队\n\n白玉兰奖揭晓 杨紫获得最佳女主角\n\n球迷整活名场面 谁是显眼包天花板\n\n西藏那曲铁路护路队：羌塘草原上的“白杨礼','',2,NULL,'中国新闻网','于晓','2026-06-27 11:09:58','https://www.chinanews.com.cn/gn/2026/06-27/10648287.shtml',4,0,0,0,'[\"politics\", \"中国新闻网\"]',1,'2026-06-27 11:11:55','2026-06-29 11:38:39','2026-06-27 11:09:58','2026-06-29 11:38:39'),(625,'中国石油河北销售分公司党委副书记郝京接受审查调查','中新网6月27日电 据中央纪委国家监委驻中国石油纪检监察组、新疆维吾尔自治区纪委监委消息：中国石油河北销售分公司党委副书记、总经理郝京涉嫌严重违纪违法，目前正接受中央纪委国家监委驻中国石油纪检监察组纪律审查和新疆维吾尔自治区监察委员会监察调查。','中新网 6月27日电 据中央纪委国家监委驻中国石油纪检监察组、新疆维吾尔自治区纪委监委消息：中国石油河北销售分公司党委副书记、总经理郝京涉嫌严重违纪违法，目前正接受中央纪委国家监委驻中国石油纪检监察组纪律审查和新疆维吾尔自治区监察委员会监察调查。\n\n董勇《繁花》的遗憾在《太平年》补上了\n\n首获白玉兰最佳女演员！杨紫想夸夸自己\n\n从传统人防到数智赋能 江西婺源宋代廊桥焕发新活力\n\n《沉默的荣耀》原型朱枫外孙女：外婆 您看到了吗？\n\n移民管理警察上勤队列 吸引中外旅客拍照点赞\n\n云南普洱集中公开销毁5.5吨毒品\n\n“世界海拔最高的千人那曲锅庄”世界纪录诞生\n\n石家庄“国字脸”网红小猴正式定名“石英俊”\n\n跨省运输活鸭“中暑” 消防水枪紧急喷淋降温\n\n幼儿园举行自理能力大赛 淡定小孩哥不慌不忙\n\n2034年能踢进世界杯吗？中国足球小将“空翻哥”的回答很棒\n\n南博会上挑战“见手青拿铁” 喝完会不会看见“小人人”\n\n河北农业大学毕业典礼上 学生轮番整活把校长“忙坏了”\n\n津台萌娃一逗一捧：“咱说的都是中国话”\n\n女子穿旗袍配高跟鞋跳绳惊艳网友\n\n登贝莱半场“戴帽” 法国队4比1战胜挪威队\n\n白玉兰奖揭晓 杨紫获得最佳女主角\n\n球迷整活名场面 谁是显眼包天花板\n\n西藏那曲铁路护路队：羌塘草原上的“白杨礼','',2,NULL,'中国新闻网','于晓','2026-06-27 11:08:54','https://www.chinanews.com.cn/gn/2026/06-27/10648288.shtml',0,0,0,0,'[\"politics\", \"中国新闻网\"]',1,'2026-06-27 11:11:56','2026-06-27 11:15:32','2026-06-27 11:08:54','2026-06-27 11:15:32'),(626,'定位生态高地中心城市 青海西宁布局“十五五”生态保护新路径','中新网西宁6月27日电 (记者 孙睿)26日，青海省“开局起步‘十五五’”主题系列新闻发布会西宁市专场召开。青海省西宁市副市长韩兴斌详解未来五年，西宁生态环保整体布局。','中新网 西宁6月27日电 (记者 孙睿)26日，青海省“开局起步‘十五五’”主题系列新闻发布会西宁市专场召开。青海省西宁市副市长韩兴斌详解未来五年，西宁生态环保整体布局。\n\n据悉，“十四五”期间，西宁市生态环境改善成效显著。立足新阶段，西宁明确了“打造生态文明高地上的中心城市”核心定位。\n\n韩兴斌介绍，西宁将统筹推进山水林田湖草沙一体化保护与修复，实施“三北”工程六期及国土绿化行动，持续提升森林覆盖率与水土保持率。推动城市优质生态资源与治理成果向乡村延伸，加快城镇污水管网向农村覆盖。巩固全域原生生活垃圾“零填埋”成果，完善环青海湖地区生活垃圾跨区域协同处理机制。\n\n持续攻坚“西宁蓝”提质行动，推进湟水流域水环境综合治理，实施国家“美丽河湖”保护与建设工程，精心打造南川河“幸福河湖”项目；加快雨污分流改造与排污口精细化管理，不断提升污水污泥处理效能，确保国省控断面水质稳定达标，将湟水河打造成全国流域生态治理标杆；深化“无废城市”建设，推动工业固体废物综合利用率持续跃升，全方位筑牢高原生态安全屏障。\n\n突出绿色转型，培育高质量发展新引擎。聚焦产业“四地”建设，全力打造国家级清洁能源产业集群，聚力推进南川国家级零碳园区建设走深走实，加快推动传统产业优化升级、重点行业绿色化改造，构建具有西宁特色的现代化产业体系；同时，健全新型能源供给保障体系，实施绿电赋能绿色制造行动，深入推动绿色算电融合发展，以绿电优势塑造城市核心竞争力。\n\n同时，西宁还将坚持生态产业化、产业生态化方向，积极探索生态产品价值实现机制，积极融入全国碳市场建设，持续深化排污权交易改革。通过深度挖掘特色生态产品的核心价值，推动高原臻品实现价值跃升，带动民众增收致富。(完)','https://i2.chinanews.com.cn/simg/ypt/2026/260627/7b3dac46-d77e-48a3-9616-0fef706875e1_zsite.jpeg',2,NULL,'中国新闻网','李岩','2026-06-27 10:34:28','https://www.chinanews.com.cn/gn/2026/06-27/10648276.shtml',0,0,0,0,'[\"politics\", \"中国新闻网\"]',1,'2026-06-27 11:11:56','2026-06-27 11:11:56','2026-06-27 10:34:28','2026-06-27 10:34:28'),(627,'我国核聚变堆超导磁体研发取得重要突破','今天(27日)，国家重大科技基础设施“聚变堆主机关键系统综合研究设施”最大的超导部件——环向场磁体完成最后制备工艺，并通过专家验收。同时，高温超导中心螺管线圈磁体也完成满工况参数测试，核心性能达到国际领先水准。','今天(27日)，国家重大科技基础设施“聚变堆主机关键系统综合研究设施”最大的超导部件——环向场磁体完成最后制备工艺，并通过专家验收。同时，高温超导中心螺管线圈磁体也完成满工况参数测试，核心性能达到国际领先水准。\n\n环向场磁体是目前国际上体积最大的聚变堆超导磁体。该磁体长21米、宽12米、高3.3米，总重量达582吨，是当前全球尺寸最大的聚变堆超导磁体。环向场磁体是大科学装置“聚变堆主机关键系统综合研究设施”最重要的部件之一。在核聚变装置运行过程中，超导磁体产生强磁场束缚上亿摄氏度高温等离子体，其中环向场磁体负责构建环向磁场来约束等离子体，减少高能粒子对真空室器壁的冲击损耗。目前，整套磁体全链条关键环节均实现国产自主可控，各项性能指标领跑国际同类产品。\n\n今天完成满工况参数测试的高温超导中心螺管线圈磁体是紧凑型聚变能实验装置的核心部件之一。该装置的核心作用是感应、驱动等离子体电流，并动态调节等离子体约束形态。目前，该磁体从超导材料、结构设计到成套制备工艺均也已实现完全国产化。\n\n这两项核心技术突破为我国建设核聚变堆筑牢了坚实的超导工程基础，将大幅提升我国相关领域的自主研发与工程建造能力。\n\n(总台央视记者 帅俊全 褚尔嘉）','',2,NULL,'中国新闻网','李岩','2026-06-27 10:04:38','https://www.chinanews.com.cn/gn/2026/06-27/10648267.shtml',0,0,0,0,'[\"politics\", \"中国新闻网\"]',1,'2026-06-27 11:11:57','2026-06-27 11:15:32','2026-06-27 10:04:38','2026-06-27 11:15:32'),(628,'拾光纪·坚持中孟友好大方向不动摇，习近平会见孟加拉国总理','6月26日，习近平主席会见孟加拉国总理塔里克。“无论国际形势如何变化，中方都将坚持中孟友好大方向不动摇”，中国不断以新发展为周边国家提供新机遇、带来新动力。','视频：拾光纪·坚持中孟友好大方向不动摇，习近平会见孟加拉国总理 来源：人民日报客户端\n\n6月26日，习近平主席会见孟加拉国总理塔里克。“无论国际形势如何变化，中方都将坚持中孟友好大方向不动摇”，中国不断以新发展为周边国家提供新机遇、带来新动力。\n\n董勇《繁花》的遗憾在《太平年》补上了\n\n首获白玉兰最佳女演员！杨紫想夸夸自己\n\n从传统人防到数智赋能 江西婺源宋代廊桥焕发新活力\n\n《沉默的荣耀》原型朱枫外孙女：外婆 您看到了吗？\n\n移民管理警察上勤队列 吸引中外旅客拍照点赞\n\n云南普洱集中公开销毁5.5吨毒品\n\n“世界海拔最高的千人那曲锅庄”世界纪录诞生\n\n石家庄“国字脸”网红小猴正式定名“石英俊”\n\n跨省运输活鸭“中暑” 消防水枪紧急喷淋降温\n\n幼儿园举行自理能力大赛 淡定小孩哥不慌不忙\n\n2034年能踢进世界杯吗？中国足球小将“空翻哥”的回答很棒\n\n南博会上挑战“见手青拿铁” 喝完会不会看见“小人人”\n\n河北农业大学毕业典礼上 学生轮番整活把校长“忙坏了”\n\n津台萌娃一逗一捧：“咱说的都是中国话”\n\n女子穿旗袍配高跟鞋跳绳惊艳网友\n\n登贝莱半场“戴帽” 法国队4比1战胜挪威队\n\n白玉兰奖揭晓 杨紫获得最佳女主角\n\n球迷整活名场面 谁是显眼包天花板\n\n西藏那曲铁路护路队：羌塘草原上的“白杨礼','',2,NULL,'中国新闻网','李岩','2026-06-27 09:32:00','https://www.chinanews.com.cn/gn/2026/06-27/10648253.shtml',0,0,0,0,'[\"politics\", \"中国新闻网\"]',1,'2026-06-27 11:11:58','2026-06-27 11:15:32','2026-06-27 09:32:00','2026-06-27 11:15:32'),(629,'天天学习｜田间地头的关切','6月24日上午，在山东德州考察的习近平总书记走进东于架村的田间地头，察粮情、聊农事。在与村民交谈中得知当地今年小麦亩产再攀新高，玉米播种不误农时，总书记当场表示祝贺。','6月24日上午，在山东德州考察的习近平总书记走进东于架村的田间地头，察粮情、聊农事。在与村民交谈中得知当地今年小麦亩产再攀新高，玉米播种不误农时，总书记当场表示祝贺。\n\n滋养万物的良田，辛勤劳作的农人，在总书记心中始终有着沉甸甸的分量。走进旱碱地麦田，他细细询问旱碱麦产量、价格、品质、收益；看到试验田里水稻长得高低不齐，他关切询问是不是品种不同；考察路上途经一片田地，他临时叫停了车，走到田间同正在劳作的乡亲们唠起家常：“现在生活上还有什么期盼？”……\n\n田间地头的关切，问的是农家事，暖的是乡亲们的心。\n\n校 对丨鲁杨 孙洁 宋春燕 梁雅琴 闫田田\n\n出 品丨中央广播电视总台央视网','',2,NULL,'中国新闻网','李岩','2026-06-27 09:31:26','https://www.chinanews.com.cn/gn/2026/06-27/10648250.shtml',0,0,0,0,'[\"politics\", \"中国新闻网\"]',1,'2026-06-27 11:11:59','2026-06-27 11:15:32','2026-06-27 09:31:26','2026-06-27 11:15:32'),(630,'学习手记｜“四下基层”践初心 人民至上创伟业','走进福建宁德霞浦县委党校旧址，“四下基层 世代相传”八个大字分外醒目。','走进福建宁德霞浦县委党校旧址，“四下基层 世代相传”八个大字分外醒目。\n\n1988年12月20日，时任宁德地委书记习近平同志就在这里同其他干部一道接待了来访群众102名，受理问题86件，其中12件当场答复解决，其余要求在一个月内处理完毕。\n\n“宣传党的路线、方针、政策下基层，调查研究下基层，信访接待下基层，现场办公下基层”——习近平同志坚持党的群众路线，大力倡导并躬身力行领导干部“四下基层”，抵达的是民心，彰显的是初心。\n\n在习近平同志看来，始终同广大人民群众保持密切的血肉联系，“这就是干部的一项十分重要的基本功”。\n\n《摆脱贫困》中有一篇文章《把心贴近人民》，这样写道：\n\n“‘功成理定何神速？速在推心置人腹。’只要各级领导能够与群众结友交心，赤诚相见，坚持从群众中来，到群众中去，我们的工作就会越做越好，我们的事业就会兴旺发达。”\n\n我们党来自人民、植根人民、服务人民，党的根基在人民、血脉在人民、力量在人民。在习近平总书记心中，“江山就是人民，人民就是江山”。\n\n常怀一颗赤子之心，一路走来，一心为民——\n\n在梁家河，习近平同志带领村民打坝淤地、修建沼气池，用一桩桩实事改善乡亲们的生活；主政正定期间，一辆“二八”自行车陪伴他跑遍全县，倾听群众心声；在浙江，推动“千万工程”，造福万千乡村；在上海调研基层社区时，接过居民编织的小牛造型工艺品，会心笑道：你是要我做服务人民的孺子牛。\n\n2012年11月，当选中共中央总书记的习近平庄严宣示：“人民对美好生活的向往，就是我们的奋斗目标。”\n\n这位泱泱大国的领航者，始终把人民放在心中最高位置。\n\n将以人民为中心贯穿治国理政全过程；亲自挂帅出征，打赢脱贫攻坚战，实现全面小康、扎实推进共同富裕，“一个也不能少”；抗击疫情，坚持“人民至上、生命至上”；擘画顶层设计，把群众意见视作“一把最好的尺子”；将改革进行到底，目的是“让发展成果更多更公平惠及全体人民”；全面从严治党，誓言“得罪千百人、不负十四亿”……\n\n从在地方工作时躬身践行“四下基层”工作制度，到在新时代治国理政中鲜明树立“人民至上”根本立场——始终与人民同呼吸、共命运、心连心的主线一以贯之，生动诠释着习近平党建思想深厚的为民底色与初心坚守。\n\n“中国共产党人的初心和使命，就是为中国人民谋幸福，为中华民族谋复兴。”\n\n6月15日召开的全国党建工作座谈会，明确提出“坚持不忘初心、牢记使命”是习近平党建思想的内涵要义之一。深入学习贯彻习近平党建思想，就要把人民放在心中最高位置，同人民风雨同舟、血脉相通、生死与共；就要牢记群众是真正的英雄，任何时候都不能忘记为了谁、依靠谁、我是谁。\n\n党的十九届六中全会把“坚持人民至上”概括为党百年奋斗的十条历史经验之一。奋进新征程，为人民谋幸福是不变的价值旨归。\n\n在“十五五”开局之年、中国共产党成立105周年之际，习近平总书记发出号召，激励广大党员干部进一步树立和践行正确政绩观——“自觉为人民出政绩、以实干出政绩”。\n\n人民至上、奋斗为民。始终如一的初心坚守中，照见的是人民领袖的千钧之诺，是百年大党的使命担当。\n\n新华社国内部、福建分社联合出品','https://i2.chinanews.com.cn/simg/cmshd/2026/06/27/9cfa3f41b4fa4685b239c53b7e5b4d5b.jpg',2,NULL,'中国新闻网','李岩','2026-06-27 09:25:50','https://www.chinanews.com.cn/gn/2026/06-27/10648245.shtml',0,0,0,0,'[\"politics\", \"中国新闻网\"]',1,'2026-06-27 11:11:59','2026-06-27 11:11:59','2026-06-27 09:25:50','2026-06-27 09:25:50'),(631,'习近平总书记在山东德州考察纪实','新华社山东德州6月25日电#8195;题：“在党的领导下把家园建设得越来越美”','新华社山东德州6月25日电 题：“在党的领导下把家园建设得越来越美”\n\n——习近平总书记在山东德州考察纪实\n\n新华社记者张晓松、朱基钗 人民日报记者杜尚泽、胡泽曦\n\n夏至刚过，平畴沃野洋溢着丰收的喜悦，又是一派播种的忙碌景象。\n\n6月24日，正值夏播时节，习近平总书记前往山东省德州市考察，深入田间地头了解粮食生产情况，来到农村调研基层党组织建设和乡村振兴，走进农民家中共话幸福生活。\n\n习近平总书记说：“这次专程来德州，就是为了看看‘三夏’生产工作的情况，看看农村的庄稼地，看看村里的乡亲们。”\n\n位于鲁西北的德州，是全国6个整区域推进高标准农田建设试点市之一，粮食年产量在150亿斤以上，约占全国的1.1%，占山东全省近14%。\n\n上午10时许，习近平总书记来到德州市陵城区边临镇东于架村的农田。\n\n德州市负责同志向总书记汇报了当地“三夏”生产情况：今年全市小麦收获面积853.7万亩，总产82.9亿斤，同比增长2%。\n\n农田边的圆形笸箩里，盛着新收的小麦，颗粒饱满、色泽明黄。习近平总书记抓起一把麦子仔细察看，关切询问麦种情况。\n\n“这个品种是济麦22，山东省农科院培育的，是这里种植面积比较大的品种。”\n\n展板上的图表，显示了2021年以来德州市深入开展“吨半粮”建设情况。“吨半粮”，顾名思义，就是通过高标准农田建设，努力实现每年亩产1500公斤粮食。\n\n“主要通过什么方式增产？”习近平总书记询问。\n\n“我们通过良种良机良法综合施策，带动全市粮食总产量从2021年的152.3亿斤，增长到2025年的157.6亿斤。”当地负责同志回答。\n\n田的命脉在水。百多公里外的黄河水，通过干渠引流至此，滋养着连片良田。\n\n习近平总书记走到灌渠边。不远处的玉米地里，通过播埋一体作业，播种机播下种子的同时，已铺设好一条条整齐的黑色滴灌管。黄河水通过泵站的净化加压，掺混肥料，流入田间实现精准滴灌。\n\n当地负责同志介绍，通过水肥一体化技术，可以实现省水、省肥、省工和增产。\n\n习近平总书记强调：“党中央和国务院高度重视高标准农田建设，每年投入大量资金给予支持，要确保质量，让广大农民真正受益。”\n\n“我提出18亿亩的耕地红线不能破，并且良田必须种粮食，为什么呢？咱们这个国家再现代化，粮食主要还是要靠自己，14亿人吃饭靠谁都靠不住，必须抓好粮食生产。”\n\n习近平总书记走进农田，同正在忙碌的种粮大户、农机手、农技人员亲切交流。\n\n“种了多少亩地？”“收成怎么样？”“收了怎样贮存？”“一亩地收入多少？”“技术上怎么指导？”“农机怎么调配？”……习近平总书记一一询问，对田间地头的事儿，关心得细致而具体。\n\n“党和政府政策好，有种粮补贴、农机补贴，还有保险补贴，都能及时到位。”种粮大户于书雷黝黑的脸上，洋溢着朴实的笑容。\n\n习近平总书记听了十分高兴，勉励大家说：“现在，夏粮有了好收成，对你们表示祝贺。秋粮也寄予希望，争取今年又是一个丰收年。大家辛苦了！祝你们的生活芝麻开花节节高。”\n\n2018年全国两会期间，正是在参加山东代表团审议时，习近平总书记明确提出推进乡村产业、人才、文化、生态、组织“五个振兴”，要求“打造各具特色的现代版富春山居图”。\n\n新征程开启，“分类有序、片区化推进乡村振兴”写入“十五五”规划纲要。齐鲁大地，铺展开乡村全面振兴的新画卷，探索着因地制宜的新做法。\n\n西于架村、东于架村、郭庄村，三个相邻村共同打造“乡村振兴德轩片区”，探索片区化推进乡村振兴的路子。\n\n在西于架村党群服务中心，做过30多年村支书的姜洪涛，向习近平总书记讲起这些年来片区里的新变化。\n\n通过党建引领，发挥西于架村、郭庄村蔬菜种植和东于架村土地资源优势，大事共商、难事共议，党员带着群众干，大家拧成一股绳，形成了合力。短短几年间，蔬菜大棚从原来的17个增加到320个，还搞起了采摘、加工、研学、直播等项目，村民人均收入翻了一番。\n\n走进一旁的农副产品直播间，“土特产”的气息扑面而来。\n\n黑小麦、绿豆粉皮、荠菜团子、小番茄、大红桃……“米袋子”“菜篮子”“果盘子”琳琅满目。习近平总书记饶有兴致，驻足察看。\n\n“村党组织建设很重要。你们这里的基层党组织还是生机勃勃的，村干部有信心、有干劲。”习近平总书记进一步叮嘱，“要再接再厉，干好本职工作，充分调动村民群众的积极性，抓好农业生产，抓好乡村全面振兴的各项工作。当前，我们正在深入开展树立和践行正确政绩观学习教育，要教育引导党员、干部坚持为民造福，多为群众做好事办实事解难事。”\n\n村民于鑫辉一家三代，在家门口热情迎接总书记。\n\n大门两侧的对联，吸引了习近平总书记的目光：家兴人兴事业兴，福旺财旺运气旺，“‘三兴三旺’，这就是人民群众的美好愿望。”\n\n客厅里围坐拉家常，于鑫辉向总书记一笔一笔细算收入账：\n\n自己在空调厂上班，每月7000多元；爱人做电商客服，每月3500元，还能就近照顾孩子；家里9.6亩地流转了，每年每亩可收830元；老人每月还能领养老金……“现在村里有蔬菜大棚，村后有产业园，只要肯干就能找到活儿、挣到钱。村里路灯亮了，通了公交车，大家下下棋、跳跳广场舞，生活一点不比城里差。”\n\n“看到你们过上好日子，我很高兴。”由一家一户、一村一镇，习近平总书记把目光投向更远，“推进城乡融合发展，逐步缩小城乡发展差距，我们一直在做，要坚定不移做下去。”\n\n起身道别，看到客厅墙上贴着于鑫辉两个女儿的一张张奖状，习近平总书记走近前仔细观看，夸赞道：“都是好孩子，将来上大学，找一个热爱的好工作，这一家子会越来越好。”\n\n热情的村民们簇拥在村口，高声向总书记问好。\n\n习近平总书记同乡亲们说：“‘七一’就要到了，我们即将迎来党的105岁生日。105年来我们党团结带领全国各族人民不懈奋斗，创造了无愧于历史和人民的伟大成就。”\n\n“我们要不忘初心、牢记使命，齐心协力走好新的长征路，开创更加光明的未来，不断满足人民对美好生活的向往。祝愿乡亲们在党的领导下把家园建设得越来越美，把日子过得越来越好。”\n\n掌声、欢呼声，在幸福的村庄里经久不息。此刻，灿烂的阳光下，村口旗杆上的五星红旗迎风高高飘扬，格外鲜艳。','',2,NULL,'中国新闻网','李岩','2026-06-27 09:24:01','https://www.chinanews.com.cn/gn/2026/06-27/10648244.shtml',0,0,0,0,'[\"politics\", \"中国新闻网\"]',1,'2026-06-27 11:12:00','2026-06-27 11:15:32','2026-06-27 09:24:01','2026-06-27 11:15:32'),(632,'一见·从多次考察党群服务中心，感悟总书记的关切','6月24日，习近平总书记在山东省德州市考察。在陵城区边临镇西于架村，习近平总书记走进村党群服务中心。','6月24日，习近平总书记在山东省德州市考察。在陵城区边临镇西于架村，习近平总书记走进村党群服务中心。\n\n把经纬线放大，将时间线拉长。在吉林长春市宽城区团山街道长山花园社区，在湖南常德市鼎城区谢家铺镇港中坪村，在重庆九龙坡区谢家湾街道民主村社区……这些年，习近平总书记进社区、访村落，多次走进当地的党群服务中心。那里，有总书记的关切。\n\n一个关切，是“抓好基层治理现代化这项基础性工作”。\n\n基层强则国家强，基层安则天下安。习近平总书记在党的二十大报告中强调：“坚持大抓基层的鲜明导向”“推进以党建引领基层治理”。\n\n党群服务中心，党建引领基层治理的实体化平台，是开展党群工作、深化基层治理的前沿阵地和重要载体，也是党联系服务群众的“最后一公里”。\n\n这里见证变化。2024年，在湖北嘉鱼县四邑村党群服务中心考察时，习近平总书记关注到墙上张贴的《服务群众事项清单》：“过去更多的是要求群众去做事，现在更多的是党员干部给群众办事、做服务，这是一个根本的变化。”\n\n这里优势显著。“社区为老百姓服务最直接，做好社区工作首先要把基层党组织建好建强”。同年，习近平总书记在宁夏银川市金凤区长城花园社区党群服务中心考察时指出，“社区要总结经验、创新思路，把为居民群众的服务做深做细做到位，努力越做越好。”\n\n这次在西于架村，习近平总书记细致询问村党组织建设和开展便民服务等情况，希望村党组织进一步发挥党建引领作用，充分调动村民群众的积极性，在推进宜居宜业和美乡村建设中不断取得新成绩。\n\n“坚持推进作风建设常态化长效化”，是习近平党建思想“十四个坚持”的一个重要方面。基层减负，镜鉴党的作风，事关基层党组织的战斗力。\n\n在西于架村，习近平总书记要求持续为基层减负，让村干部有更多时间和精力服务群众、推动发展。\n\n回望这些年在党群服务中心考察的点滴细节，肯定什么，反对什么，态度鲜明：\n\n湖南常德市鼎城区谢家铺镇港中坪村，村部的牌子，从最多时的38块减少到12块。习近平总书记给予肯定：“党中央明确要求为基层减负，要坚决整治形式主义、官僚主义问题，精兵简政，持之以恒把这项工作抓下去。”\n\n“前天去九龙坡，我问社区党委书记，现在负担重不重。她说，过去填很多报表，通过报表开展工作。那不行。”在重庆考察时，习近平总书记谈到为基层减负：“不能形式大于内容，表面大于实效。形式主义少一些、真抓实干多一些，矛盾也会少一些，实绩也会多一些。”\n\n多次走进党群服务中心，听实话、察实情、求实效，归根结底关切的是民生福祉。\n\n“村里有几个卫生室？”“都是全科医生吗？”2019年，习近平总书记来到甘肃古浪县黄花滩生态移民区富民新村党群服务中心便民大厅，询问各项惠民政策落实情况和易地扶贫搬迁后的便民服务措施。\n\n2020年，习近平总书记来到吉林长春市宽城区长山花园社区社区党群服务中心。居民告诉总书记，小区通了天然气，装了健身器材，建了诊疗室，有困难找得着组织……“看到你们安居乐业、其乐融融的景象，我很欣慰。”总书记勉励社区工作者，再接再厉，寓管理于服务之中，进一步搞好为民服务各项工作，把家园建设得更加幸福美好。\n\n树立和践行正确政绩观，最终要落到为民造福上。“广大党员、干部要强化公仆意识，厚植为民情怀，多为群众做好事、办实事、解难事，实实在在增强老百姓的获得感幸福感安全感。”这次在西于架村，习近平总书记强调。\n\n一头连着基层党建，一头连着服务群众。一个个党群服务中心，微观看是方寸之地，宏观理解是“血肉联系”连点成面的关键所在。\n\n“密切党群、干群关系，保持同人民群众的血肉联系，始终是我们党立于不败之地的根基。”习近平总书记深刻指出。','https://i2.chinanews.com.cn/simg/cmshd/2026/06/27/98f8130bf82f4ca39b6a249659cde25f.jpeg',2,NULL,'中国新闻网','李岩','2026-06-27 09:22:55','https://www.chinanews.com.cn/gn/2026/06-27/10648242.shtml',0,0,0,0,'[\"politics\", \"中国新闻网\"]',1,'2026-06-27 11:12:01','2026-06-27 11:12:01','2026-06-27 09:22:55','2026-06-27 09:22:55'),(633,'中央安全生产考核巡查组第九组向山西省反馈明查暗访情况','中央安全生产考核巡查组第九组向山西省反馈明查暗访情况','中央安全生产考核巡查组第九组向山西省反馈明查暗访情况\n\n唐登杰作表态发言 李兴湖通报情况 卢东亮主持\n\n本报讯 为深入贯彻落实习近平总书记关于安全生产的重要指示批示精神，根据《安全生产考核巡查办法》，中央安全生产考核巡查组第九组于6月11日至25日对山西省开展了安全生产考核巡查明查暗访。6月24日，考核巡查组第九组组长李兴湖向山西省反馈明查暗访情况，省委书记唐登杰作表态发言，省委副书记、省长卢东亮主持，省委常委、常务副省长董晓宇出席。\n\n考核巡查组指出，山西省委、省政府深入学习贯彻习近平总书记关于安全生产的重要指示批示精神，坚决扛起安全生产政治责任，组织开展煤矿安全风险隐患专项整治行动，统筹做好各领域安全生产工作。本次明查暗访发现了一些问题隐患，主要是统筹发展和安全不够到位，部门间监管合力效果不明显、隐患排查不深不细，煤矿领域非法违法问题依然严重，群众身边的消防安全隐患突出，道路运输超速和疲劳驾驶等现象普遍，重点领域安全管理仍有不足，反映出安全生产工作还存在一些薄弱环节，务必引起高度重视。\n\n考核巡查组强调，山西省要深刻汲取“5·22”沁源煤矿瓦斯爆炸事故教训，严格落实矿山安全“八条硬措施”，加强消防、道路运输、建筑施工、危化、工贸、燃气等重点领域隐患排查整治，牢牢守住安全底线。要深入推进安全生产治本攻坚三年行动，加强安全教育培训，推动安全监管精准化、智能化，着力提升固本强基质效。要持续强化监管执法力度，严格落实“行刑衔接”，推动行业生态持续向好。要立足防大汛、抗大旱、抢大险、救大灾，扎实做好汛期安全风险防范。\n\n考核巡查组指出，地方党政主要负责同志是本地区安全生产工作的第一责任人，也是问题隐患整改的第一责任人。要深入贯彻落实习近平总书记关于安全生产的重要指示批示精神，按照党中央、国务院决策部署，结合开展树立和践行正确政绩观学习教育，切实抓好明查暗访反馈问题隐患整改，对违法违规行为严肃追责问责并依法依规落实行刑衔接，按时反馈调查处理、追责问责和整改落实情况，坚决防范遏制重特大事故发生，切实保障人民群众生命安全和社会大局稳定。\n\n省委书记唐登杰表示，中央安全生产考核巡查组第九组莅晋开展工作，充分体现了对山西安全生产工作和各项事业发展的高度重视和关心指导。考核巡查组精准深入把脉问诊，指出的问题隐患直击要害，提出的整改要求具体明确，山西省委、省政府照单全收、坚决整改、彻底整改。我们要深入学习贯彻习近平总书记关于安全生产的重要指示批示精神，坚持人民至上、生命至上，牢固树立安全发展理念，狠抓安全生产各项工作落实，坚决防范遏制重特大事故发生。要把考核巡查反馈意见整改落实作为重要政治任务，加紧制定整改方案，抓细抓实线索核查和交办单办理，层层压实工作责任，持续强化跟踪问效，确保反馈意见条条落实、件件落地。要坚持“当下改”与“长久立”相结合，加快补齐制度短板、堵塞监管漏洞、打通堵点卡点，常态长效推动标本兼治。要深刻汲取“5·22”沁源煤矿瓦斯爆炸事故教训，深入开展煤矿安全风险隐患专项整治行动，统筹抓好各领域安全防范和防灾减灾工作，全力推动安全生产形势稳定向好。要以中央考核巡查整改为重要契机，结合开展树立和践行正确政绩观学习教育，推动各级领导干部增强安全生产责任意识，强化基层应急管理能力，不断提升本质安全水平，以高水平安全保障高质量发展。\n\n考核巡查组现场向山西省委省政府移交了重大事故隐患追责问责交办单。专项检查组检查发现的涉及党员干部违纪违法问题线索，将按照干部管理权限移交相关纪检监察机关处置。\n\n中央安全生产考核巡查组第九组有关成员，省纪委监委有关负责同志，部分市委书记，省直有关部门和省安委会有关成员单位负责同志参加会议。(本报记者）','',2,NULL,'中国新闻网','于晓','2026-06-27 08:41:01','https://www.chinanews.com.cn/gn/2026/06-27/10648233.shtml',0,0,0,0,'[\"politics\", \"中国新闻网\"]',1,'2026-06-27 11:12:01','2026-06-27 11:15:32','2026-06-27 08:41:01','2026-06-27 11:15:32'),(634,'世界首台、全球领先！本周，我国多领域解锁硬核成就','中国超算“灵晟”登顶全球榜首','6月23日，德国汉堡国际超算大会发布全球超算TOP500榜单。全国产自主研制的“灵晟”超级计算机以2.19EFlops持续双精度浮点性能，登顶全球超算TOP500。时隔九年，我国超算再次排名全球第一。\n\n2.19EFlops，即每秒钟完成219亿亿次浮点运算，相当于70亿人以每秒完成1次的运算速度，需要昼夜不停计算10年。而这个计算量，“灵晟”做到了，这也是世界首台持续性能超二百亿亿次的超算系统。\n\n国产高端存储技术达全球领先水平\n\n同样是在德国汉堡国际超算大会上，由我国自主研制的中科曙光ParaStor F9000全闪存储系统，在IO500榜单的生产型全节点和10节点榜中实现双榜第一，再次证明国产高端存储性能达到全球领先水平。\n\n对大规模AI集群而言，存储系统的重要性正不断提升。在极端并发访问和海量数据吞吐条件下，ParaStor F9000能够持续稳定地向计算节点提供数据支撑，保障大规模集群高效运行。自中国国家超算互联网核心节点启动建设以来，ParaStor F9000已投入实际生产环境。目前，该系统在大模型训练、科学计算与数据分析等关键场景中提供支撑。\n\nIO500是高性能计算与人工智能领域权威的存储系统性能基准测试榜单。此次评测中，ParaStor F9000同时位列两大生产型榜单第一，证明国产高端存储技术已在全球算力体系中具有领先实力，也为我国构建人工智能时代高性能、高可靠的“存力”提供了坚实基础。\n\n日前，新疆吉木萨尔全钒液流电池储能电站全面转入商业运行。该电站是我国目前规模最大的全钒液流电池储能电站，标志着我国在大容量、长时储能技术规模化应用方面取得新进展。\n\n全钒液流电池是一种长时储能技术，主要通过电解液中钒离子价态变化，实现电能储存和释放，具有安全性高、循环寿命长、扩容能力强等特点。新疆吉木萨尔全钒液流电池储能电站由储能单元、能量转换单元和动力系统等组成，相当于为光伏发电配套建设了一座“巨型充电宝”。\n\n我国是全球钒资源储量最丰富、产能规模最大、消费市场最广的国家，资源储备可长期支撑产业发展需求。随着我国能源绿色转型的加速，风电、光伏等新能源装机规模持续快速增长。全钒液流储能作为支撑高比例可再生能源发展的战略性技术，正迎来技术突破与产业落地的双重加速阶段。\n\n6月26日，拥有世界第一高坝的大渡河双江口水电站，迎来首台机组并网发电，为西南地区清洁能源供应体系建设和我国“双碳”目标落地再添新的支撑。\n\n大渡河流域是我国第五大水电基地，水能资源富集、开发潜力巨大。双江口水电站装机200万千瓦，作为大渡河流域上游控制性龙头水库，建成后，将整体提升大渡河流域防洪、发电综合效益，成为长江上游重要的安全屏障和能源枢纽，在清洁能源供应、绿色转型与区域发展中展现出更强劲的动能。\n\n2.4万箱甲醇双燃料集装箱船交付启航\n\n6月26日，全球首制2.4万箱甲醇双燃料集装箱船“东方智慧”轮从江苏南通长江段码头交付启航。\n\n据船舶技术人员介绍，作为目前全球最大级别的甲醇双燃料集装箱船，该船舶搭载先进甲醇双燃料动力系统，使用绿色甲醇时碳排放显著降低，兼具大型化、低碳化、智能化技术优势，是我国清洁能源船舶制造领域的突破性产品。\n\n6月25日23时59分，总装机容量170万千瓦的天台抽水蓄能电站实现全面投产发电，这也是“十五五”期间国内首个全面投产的抽水蓄能电站。\n\n电站拥有724米的额定水头，为目前世界同类项目之最；\n\n安装4台42.5万千瓦的可逆式水轮发电机组，单机容量位居国内抽水蓄能机组首位；\n\n其单级引水斜井长度达483米，创国内同类工程纪录。\n\n天台抽水蓄能电站全面投产后，将主要承担浙江电网的调峰、填谷、调频、调相、储能及紧急事故备用等任务，预计每年可提供约17亿千瓦时的高峰电能，可满足约160万人一年的生活用电需求，相当于每年节约标准煤约52万吨，减少二氧化碳排放约104万吨，可显著增强浙江电网的调节能力与应急保供韧性。','https://i2.chinanews.com.cn/simg/cmshd/2026/06/27/7c7b527df0824fd4962349a20b6befc4.png',2,NULL,'中国新闻网','李岩','2026-06-27 08:25:54','https://www.chinanews.com.cn/gn/2026/06-27/10648226.shtml',0,0,0,0,'[\"politics\", \"中国新闻网\"]',1,'2026-06-27 11:12:02','2026-06-27 11:12:02','2026-06-27 08:25:54','2026-06-27 08:25:54'),(635,'几内亚总理访沪 冀进一步加强与上海的合作交流','中新社上海6月26日电 (许婧 狄权)正在上海访问的几内亚总理乌里·巴表示，几内亚非常关注上海，在这里可以看到世界的未来，希望进一步加强与上海的合作交流。','中新社 上海6月26日电 (许婧 狄权)正在上海访问的几内亚总理乌里·巴表示，几内亚非常关注上海，在这里可以看到世界的未来，希望进一步加强与上海的合作交流。\n\n26日，乌里·巴到访上海中共一大会址，随后走进中共一大纪念馆新馆，参观“伟大的开端——中国共产党创建历史陈列”。其间，他认真聆听讲解，频频点头，并在馆内留言：“在人类历史上，这场革命无疑是最卓越的篇章之一。我们向那些铸就中国及其人民命运的先辈们致以崇高敬意。”\n\n此次访沪，乌里·巴不仅走进红色地标，也深入企业，看技术、谈合作。25日，他参观考察宝山再生能源利用中心、宝武钢铁集团，了解上海绿色循环经济与先进钢铁产业发展成果。在宝山再生能源利用中心，乌里·巴称，如果能与拥有先进技术的中国伙伴合作，迅速找到垃圾处理的解决方案，“那就太好了”。\n\n几内亚是同新中国建交的第一个撒哈拉以南非洲国家。在沪期间，乌里·巴表示，上海是中国共产党的诞生地，也是中国现代化建设的标志性城市。上海的发展成就令人印象深刻，在众多领域都展现出全球领先水平。只要是有利于改善生活质量、增进人民福祉的事业，上海都在大力投入，这值得包括几内亚在内的很多国家学习。\n\n根据上海海关统计，今年一季度，上海口岸对非洲进出口1240.5亿元人民币，同比增长36.7%，其中，进口出口分别同比增长62.2%和23.7%。\n\n上海官方表示，希望以高质量共建“一带一路”为机遇，进一步加强与几内亚的交流合作，实现更高水平的互利共赢，为两地人民谋取更大福祉。期待双方加强能源、科技创新、港口物流、基础设施建设、气候治理等领域合作，支持优秀企业到对方投资兴业，共享发展机遇。热忱欢迎几内亚企业继续参加中国国际进口博览会。今年是中非人文交流年，希望以此为契机，进一步深化双方在文化、教育、旅游等领域的交流合作，推动双方民众加深了解、增进友谊。(完)','',2,NULL,'中国新闻网','田博群','2026-06-26 23:39:19','https://www.chinanews.com.cn/gn/2026/06-26/10648210.shtml',0,0,0,0,'[\"politics\", \"中国新闻网\"]',1,'2026-06-27 11:12:02','2026-06-27 11:15:32','2026-06-26 23:39:19','2026-06-27 11:15:32'),(636,'习言道｜扎实推进中柬命运共同体建设','6月26日，中共中央总书记、国家主席习近平在人民大会堂会见柬埔寨人民党主席、参议院主席洪森。习近平指出——','6月26日，中共中央总书记、国家主席习近平在人民大会堂会见柬埔寨人民党主席、参议院主席洪森。习近平指出——\n\n董勇《繁花》的遗憾在《太平年》补上了\n\n首获白玉兰最佳女演员！杨紫想夸夸自己\n\n从传统人防到数智赋能 江西婺源宋代廊桥焕发新活力\n\n《沉默的荣耀》原型朱枫外孙女：外婆 您看到了吗？\n\n移民管理警察上勤队列 吸引中外旅客拍照点赞\n\n云南普洱集中公开销毁5.5吨毒品\n\n“世界海拔最高的千人那曲锅庄”世界纪录诞生\n\n石家庄“国字脸”网红小猴正式定名“石英俊”\n\n跨省运输活鸭“中暑” 消防水枪紧急喷淋降温\n\n幼儿园举行自理能力大赛 淡定小孩哥不慌不忙\n\n2034年能踢进世界杯吗？中国足球小将“空翻哥”的回答很棒\n\n南博会上挑战“见手青拿铁” 喝完会不会看见“小人人”\n\n河北农业大学毕业典礼上 学生轮番整活把校长“忙坏了”\n\n津台萌娃一逗一捧：“咱说的都是中国话”\n\n女子穿旗袍配高跟鞋跳绳惊艳网友\n\n登贝莱半场“戴帽” 法国队4比1战胜挪威队\n\n白玉兰奖揭晓 杨紫获得最佳女主角\n\n球迷整活名场面 谁是显眼包天花板\n\n西藏那曲铁路护路队：羌塘草原上的“白杨礼','https://i2.chinanews.com.cn/simg/cmshd/2026/06/26/749099f55b0d4dfe9f368802478aa62d.jpg',2,NULL,'中国新闻网','田博群','2026-06-26 23:29:30','https://www.chinanews.com.cn/gn/2026/06-26/10648207.shtml',0,0,0,0,'[\"politics\", \"中国新闻网\"]',1,'2026-06-27 11:12:03','2026-06-27 11:12:03','2026-06-26 23:29:30','2026-06-26 23:29:30'),(637,'受权发布丨全国人民代表大会常务委员会任免名单','新华社北京6月26日电','全国人民代表大会常务委员会任免名单\n\n(2026年6月26日第十四届全国人民代表大会常务委员会第二十三次会议通过)\n\n一、免去齐素(女)的最高人民法院刑事审判第三庭副庭长、审判员职务。\n\n二、任命向黎丽(女)、宋志彪、张安品(女)为最高人民法院审判员。\n\n三、免去胡立新、李智明、于同志、何鹏、赵静莉(女)、王方、廖国娟(女)、方丽达(女)的最高人民法院审判员职务。\n\n董勇《繁花》的遗憾在《太平年》补上了\n\n首获白玉兰最佳女演员！杨紫想夸夸自己\n\n从传统人防到数智赋能 江西婺源宋代廊桥焕发新活力\n\n《沉默的荣耀》原型朱枫外孙女：外婆 您看到了吗？\n\n移民管理警察上勤队列 吸引中外旅客拍照点赞\n\n云南普洱集中公开销毁5.5吨毒品\n\n“世界海拔最高的千人那曲锅庄”世界纪录诞生\n\n石家庄“国字脸”网红小猴正式定名“石英俊”\n\n跨省运输活鸭“中暑” 消防水枪紧急喷淋降温\n\n幼儿园举行自理能力大赛 淡定小孩哥不慌不忙\n\n2034年能踢进世界杯吗？中国足球小将“空翻哥”的回答很棒\n\n南博会上挑战“见手青拿铁” 喝完会不会看见“小人人”\n\n河北农业大学毕业典礼上 学生轮番整活把校长“忙坏了”\n\n津台萌娃一逗一捧