DROP TABLE IF EXISTS `news_topic`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `news_topic` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT '话题ID',
  `topic_name` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '话题名称',
  `summary` text COLLATE utf8mb4_unicode_ci COMMENT '话题简介',
  `keyword_list` json DEFAULT NULL COMMENT '关键词列表',
  `heat_score` int NOT NULL DEFAULT '0' COMMENT '热度分',
  `status` tinyint NOT NULL DEFAULT '1' COMMENT '状态：1启用，0禁用',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_news_topic_status_heat` (`status`,`heat_score`),
  KEY `idx_news_topic_name` (`topic_name`)
) ENGINE=InnoDB AUTO_INCREMENT=14 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='新闻话题表';
