INSERT INTO `news_topic` VALUES (1,'人工智能技术发展','围绕人工智能、大模型、智能应用等方向的相关新闻事件脉络。','[\"人工智能\", \"大模型\", \"AI\", \"智能应用\"]',100,1,'2026-06-27 11:40:43','2026-06-27 11:40:43'),(2,'低空经济与无人机产业','围绕低空经济、无人机产业、空域管理等方向的相关新闻事件脉络。','[\"低空经济\", \"无人机\", \"空域\", \"飞行器\"]',80,1,'2026-06-27 11:40:43','2026-06-27 11:40:43'),(3,'新能源汽车与智能交通','围绕新能源汽车、智能驾驶、交通出行等方向的相关新闻事件脉络。','[\"新能源汽车\", \"智能交通\", \"自动驾驶\", \"充电\"]',70,1,'2026-06-27 11:40:43','2026-06-27 11:40:43');
