INSERT INTO `post_comment` VALUES (1,1,2,NULL,'我更倾向先看短摘要，再决定是否阅读全文。尤其是长篇科技新闻，摘要能帮我快速抓重点。',NULL,4,1,'2026-06-27 11:54:22','2026-06-20 09:35:00','2026-06-20 09:35:00','2026-06-29 17:17:52'),(2,1,3,NULL,'如果能同时给出“核心事实”和“可能影响”，会比单纯压缩正文更有价值。',NULL,3,1,'2026-06-27 11:54:22','2026-06-20 09:50:00','2026-06-20 09:50:00','2026-06-29 17:17:52'),(3,1,1,2,'同意，尤其是财经新闻，影响分析很重要，但也要标明是系统生成结果。',NULL,2,1,'2026-06-27 11:54:22','2026-06-20 10:05:00','2026-06-20 10:05:00','2026-06-29 17:17:52'),(4,2,1,NULL,'低空经济很适合做时间线，政策和应用场景变化都比较明显。',NULL,5,1,'2026-06-27 11:54:22','2026-06-30 09:38:46','2026-06-20 11:45:00','2026-06-30 09:38:46'),(5,2,3,4,'可以把“政策发布、试点落地、产业园建设”作为节点类型，阅读会更清楚。',NULL,3,1,'2026-06-27 11:54:22','2026-06-20 12:02:00','2026-06-20 12:02:00','2026-06-29 17:17:52'),(6,3,1,NULL,'个人中心的阅读脉络如果能按话题聚合，会比单纯列表更有帮助。',NULL,4,1,'2026-06-27 11:54:22','2026-06-21 14:45:00','2026-06-21 14:45:00','2026-06-29 17:17:52'),(7,3,2,NULL,'新能源新闻还可以和时间线联动，看政策、企业、基础设施之间的关系。',NULL,2,1,'2026-06-27 11:54:22','2026-06-21 14:58:00','2026-06-21 14:58:00','2026-06-29 17:17:52'),(8,4,3,NULL,'关联新闻很有必要，不然社区讨论容易变成泛泛聊天。',NULL,3,1,'2026-06-27 11:54:22','2026-06-22 09:00:00','2026-06-22 09:00:00','2026-06-29 17:17:52'),(9,4,1,8,'后续可以在详情页增加“参与讨论”入口，直接带上新闻 id。',NULL,2,1,'2026-06-27 11:54:22','2026-06-22 09:18:00','2026-06-22 09:18:00','2026-06-29 17:17:52'),(10,5,3,NULL,'待审核和折叠状态最好在后台能筛选，这样演示逻辑更完整。',NULL,1,1,'2026-06-27 11:54:22','2026-06-22 16:35:00','2026-06-22 16:35:00','2026-06-29 17:17:52'),(41,2,1,NULL,'11111',NULL,1,1,'2026-06-27 11:56:05','2026-06-30 09:37:55','2026-06-27 11:56:05','2026-06-30 09:37:55'),(42,2,1,NULL,'🙂‍↕️🙂‍↕️🙂‍↕️🙂‍↕️😌😌😔😪',NULL,0,1,'2026-06-29 09:09:53','2026-06-29 09:09:53','2026-06-29 09:09:53','2026-06-29 09:09:53'),(43,26,3,NULL,'哈哈哈哈哈哈',NULL,0,1,'2026-06-29 09:52:02','2026-06-29 09:52:02','2026-06-29 09:52:02','2026-06-29 09:52:02'),(44,26,3,NULL,'哈哈哈哈哈哈哈',NULL,0,1,'2026-06-29 09:52:06','2026-06-29 09:52:06','2026-06-29 09:52:06','2026-06-29 09:52:06'),(45,26,3,NULL,'哈哈哈哈哈哈哈',NULL,0,1,'2026-